              </div>
              <span className="font-display text-xl font-bold tracking-tight">AI Tutor</span>
            </div>

            <div className="space-y-4 text-center lg:text-left animate-fade-up">
              <div className="inline-flex items-center gap-2 rounded-full border border-primary/20 bg-primary/5 px-3 py-1 text-xs font-semibold text-primary">
                <Sparkles className="h-3 w-3" />
                <span>Next Gen Learning</span>
              </div>
              <h1 className="font-display text-4xl font-bold tracking-tight text-foreground sm:text-5xl lg:text-6xl leading-[1.1]">
                Master any subject <br />
                <span className="text-gradient">with AI guidance</span>
              </h1>
              <p className="text-lg text-muted-foreground max-w-md mx-auto lg:mx-0">
                Experience a personalized learning journey that adapts to your pace. 
                Get real-time feedback, deep insights, and structured curriculum.
              </p>
            </div>

            {/* Auth Card */}
            <div className="panel-glass rounded-2xl p-8 shadow-xl border border-border/50 animate-scale-in delay-200">
              <div className="mb-6">
                <h2 className="text-xl font-semibold font-display text-foreground flex items-center gap-2">
                  <span className="flex h-8 w-8 items-center justify-center rounded-lg bg-secondary text-foreground">
                    <BookOpen className="h-4 w-4" />
                  </span>
                  Welcome back
                </h2>
                <p className="text-sm text-muted-foreground mt-1 ml-10">
                  Sign in to continue your progress
                </p>
              </div>

              {error && (
                <div className="mb-6 animate-fade-in flex items-start gap-3 rounded-lg border border-destructive/20 bg-destructive/5 p-3 text-sm text-destructive">
                   <div className="mt-0.5">
                     <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                     </svg>
                   </div>
                   <p>{error}</p>
                </div>
