34. export default function InstructorCourseModules({ loaderData }: Route.ComponentProps) {
35.   const navigate = useNavigate();
36.   const { courseId } = useParams();
37.   const numericCourseId = courseId ? Number(courseId) : null;
38.   const { course, modules: initialModules } = loaderData;
39.   const [modules, setModules] = useState<Module[]>(initialModules);
40.   const [title, setTitle] = useState('');
41.   const [creating, setCreating] = useState(false);
42.   const [showImport, setShowImport] = useState(false);
43.   const [availableCourses, setAvailableCourses] = useState<Course[]>([]);
44.   const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
45.   const [sourceModules, setSourceModules] = useState<Module[]>([]);
46.   const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
47.   const [loadingSourceModules, setLoadingSourceModules] = useState(false);
48.   const [selectedModuleIds, setSelectedModuleIds] = useState<Set<number>>(new Set());
49.   const [importing, setImporting] = useState(false);
50.   const [publishingId, setPublishingId] = useState<number | null>(null);
51.   const modulesRequestIdRef = useRef(0);
52. 
53.   const [oModules, addModuleOpt] = useOptimistic(
54.     modules,
55.     (state, patch: (items: Module[]) => Module[]) => patch(state),
56.   );
57. 
58.   // Adjust state during render when loader data changes
59.   const [prevInitialModules, setPrevInitialModules] = useState(initialModules);
60.   if (initialModules !== prevInitialModules) {
61.     setPrevInitialModules(initialModules);
62.     setModules(initialModules);
63.   }
64. 
65.   const refreshModules = async () => {
66.     if (!numericCourseId) return;
67.     try {
68.       const modulesData = await api.modulesForCourse(numericCourseId);
69.       setModules(modulesData);
70.     } catch (error) {
71.       console.error('Failed to refresh modules', error);
72.     }
73.   };
74. 
75.   const ensureSourceCoursesLoaded = () => {
76.     if (availableCourses.length > 0) return;
77.     setLoadingSourceCourses(true);
78.     api
79.       .listCourses()
80.       .then((data: Course[]) => {
81.         const nextCourses = numericCourseId
82.           ? data.filter((course: Course) => course.id !== numericCourseId)
83.           : data;
84.         setAvailableCourses(nextCourses);
85.       })
86.       .catch((error) => console.error('Failed to load courses', error))
87.       .finally(() => setLoadingSourceCourses(false));
88.   };
89. 
90.   const handleSourceCourseSelection = async (nextCourseId: number | null) => {
91.     const requestId = ++modulesRequestIdRef.current;
92.     setSelectedSourceCourseId(nextCourseId);
93.     setSourceModules([]);
94.     setSelectedModuleIds(new Set());
95. 
96.     if (nextCourseId == null) {
97.       setLoadingSourceModules(false);
98.       return;
99.     }
100. 
101.     setLoadingSourceModules(true);
102.     try {
103.       const data = await api.modulesForCourse(nextCourseId);
104.       if (modulesRequestIdRef.current === requestId) {
105.         setSourceModules(data);
106.       }
107.     } catch (error) {
108.       if (modulesRequestIdRef.current === requestId) {
109.         console.error('Failed to load modules for course', error);
110.         setSourceModules([]);
111.       }
112.     } finally {
113.       if (modulesRequestIdRef.current === requestId) {
114.         setLoadingSourceModules(false);
115.       }
116.     }
117.   };
118. 
119.   const onCreateModule = async (event: FormEvent) => {
120.     event.preventDefault();
121.     if (!numericCourseId || !title.trim()) return;
122.     setCreating(true);
123.     try {
124.       await api.createModule(numericCourseId, { title: title.trim() });
125.       setTitle('');
126.       await refreshModules();
127.     } catch (error) {
128.       console.error('Failed to create module', error);
129.     } finally {
130.       setCreating(false);
131.     }
132.   };
133. 
134.   const toggleModuleSelection = (moduleId: number) => {
135.     setSelectedModuleIds((prev) => {
136.       const next = new Set(prev);
137.       if (next.has(moduleId)) next.delete(moduleId);
138.       else next.add(moduleId);
139.       return next;
140.     });
141.   };
142. 
143.   const onImport = async () => {
144.     if (!numericCourseId || selectedSourceCourseId == null || selectedModuleIds.size === 0) return;
145.     setImporting(true);
146.     try {
147.       await api.importIntoCourse(numericCourseId, {
148.         sourceCourseId: selectedSourceCourseId,
149.         moduleIds: Array.from(selectedModuleIds),
150.       });
151.       setShowImport(false);
152.       await handleSourceCourseSelection(null);
153.       await refreshModules();
154.     } catch (error) {
155.       console.error('Import failed', error);
156.     } finally {
157.       setImporting(false);
158.     }
159.   };
160. 
161. 
162.   const togglePublish = async (moduleId: number, currentlyPublished: boolean) => {
163.     // Optimistic update via useOptimistic
164.     addModuleOpt((items) =>
165.       items.map((m) => (m.id === moduleId ? { ...m, isPublished: !currentlyPublished } : m)),
166.     );
