170.       const updated = currentlyPublished
171.         ? await api.unpublishModule(moduleId)
172.         : await api.publishModule(moduleId);
173.       // Confirm with server response
174.       setModules((prev) => prev.map((m) => (m.id === moduleId ? updated : m)));
175.     } catch (error) {
176.       console.error('Failed to toggle publish status', error);
177.       // Rollback on error to clear optimistic change
178.       setModules((prev) =>
179.         prev.map((m) => (m.id === moduleId ? { ...m, isPublished: currentlyPublished } : m)),
180.       );
181.     } finally {
182.       setPublishingId((current) => (current === moduleId ? null : current));
183.     }
184.   };
185. 
