224.               <div>
225.                 <label className="block text-sm font-semibold mb-1 text-foreground">Choose course to copy</label>
226.                 <select
227.                   value={selectedSourceCourseId ?? ''}
228.                   onChange={(e) => {
229.                     const nextValue = e.target.value ? Number(e.target.value) : null;
230.                     void handleSourceCourseSelection(nextValue);
231.                   }}
232.                   className="input-field"
233.                 >
