               onChange={(e) => setTitle(e.target.value)}
               placeholder="New module title…"
               className="input-field flex-1"
             />
             <button
               disabled={creating || !title.trim()}
               className="btn-primary"
             >
               {creating ? 'Adding…' : 'Add Module'}
             </button>
           </form>

