import { useOptimistic, useState } from 'react';
import { useNavigate } from 'react-router';
import Nav from '../components/Nav';
import { PublishStatusButton } from '../components/PublishStatusButton';
import api from '../lib/api';
import type { Course, EduAiCourse } from '../lib/types';
import type { Route } from './+types/instructor';
import { requireClientUser } from '~/lib/client-auth';
import { 
  PlusCircle, 
  Search, 
  MoreVertical, 
  Users, 
  BookOpen, 
  GraduationCap, 
  BarChart3,
  Sparkles,
  ArrowRight
} from 'lucide-react';
import { FloatingNode } from '~/components/DesignSystem';

export async function clientLoader(_: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const courses = (await api.listCourses()) as Course[];
  return { courses };
}

export default function InstructorHome({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const [courses, setCourses] = useState<Course[]>(loaderData.courses ?? []);
  const [loading, setLoading] = useState(false);
  const [showEduAiImport, setShowEduAiImport] = useState(false);
  const [publishingId, setPublishingId] = useState<number | null>(null);
  const [eduAiCourses, setEduAiCourses] = useState<EduAiCourse[]>([]);
  const [loadingEduAiCourses, setLoadingEduAiCourses] = useState(false);
  const [importingExternalId, setImportingExternalId] = useState<string | null>(null);
  const [eduAiError, setEduAiError] = useState<string | null>(null);

  const [oCourses, addCourseOpt] = useOptimistic(
    courses,
    (state, patch: (items: Course[]) => Course[]) => patch(state),
  );

  const parseErrorMessage = (error: unknown) => {
    if (error instanceof Error) {
      try {
        const parsed = JSON.parse(error.message);
        if (parsed && typeof parsed === 'object' && typeof parsed.error === 'string') {
          return parsed.error;
        }
      } catch {
        // Ignore JSON parse failures
      }
      return error.message;
    }
    return 'Something went wrong. Please try again.';
  };

  const loadCourses = async () => {
    setLoading(true);
    try {
      const data: Course[] = await api.listCourses();
      setCourses(data);
    } catch (error) {
      console.error('Failed to load courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchEduAiCourses = async () => {
    setLoadingEduAiCourses(true);
    setEduAiError(null);
    try {
      const data = (await api.listEduAiCourses()) as EduAiCourse[];
      setEduAiCourses(data);
    } catch (error) {
      console.error('Failed to load EduAI courses:', error);
      setEduAiError(parseErrorMessage(error));
    } finally {
      setLoadingEduAiCourses(false);
    }
  };

  const ensureEduAiCourses = () => {
    if (eduAiCourses.length > 0 || loadingEduAiCourses) return;
    fetchEduAiCourses();
  };

  const importEduAiCourse = async (externalCourseId: string) => {
    if (!externalCourseId) return;
    setImportingExternalId(externalCourseId);
    setEduAiError(null);
    try {
      await api.importEduAiCourse({ externalCourseId });
      setEduAiCourses((prev) => prev.filter((course) => course.id !== externalCourseId));
      await loadCourses();
    } catch (error) {
      console.error('Failed to import EduAI course:', error);
      setEduAiError(parseErrorMessage(error));
    } finally {
      setImportingExternalId((current) => (current === externalCourseId ? null : current));
    }
  };

  const togglePublish = async (courseId: number, currentlyPublished: boolean) => {
    addCourseOpt((items) =>
      items.map((course) =>
        course.id === courseId ? { ...course, isPublished: !currentlyPublished } : course,
      ),
    );
    setPublishingId(courseId);

    try {
      const updated = currentlyPublished
        ? await api.unpublishCourse(courseId)
        : await api.publishCourse(courseId);
      setCourses((prev) =>
        prev.map((course) => (course.id === courseId ? updated : course))
      );
    } catch (error) {
      console.error('Failed to toggle publish status', error);
      setCourses((prev) =>
        prev.map((course) =>
          course.id === courseId ? { ...course, isPublished: currentlyPublished } : course,
        ),
      );
    } finally {
      setPublishingId((current) => (current === courseId ? null : current));
    }
  };

  return (
    <div className="min-h-dvh bg-background">
      <Nav />

      {/* Immersive Header Section */}
      <div className="relative overflow-hidden border-b border-border/40 bg-muted/20 pb-20 pt-16">
        <div className="absolute inset-0 dots-pattern opacity-30" />
        <div className="absolute -top-24 -right-24 h-96 w-96 rounded-full bg-primary/5 blur-3xl" />
        <div className="absolute top-1/2 left-1/4 h-64 w-64 rounded-full bg-accent/5 blur-3xl" />

        <div className="container relative mx-auto px-6">
          <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-8">
            <div className="max-w-2xl animate-fade-up">
              <div className="mb-4 inline-flex items-center gap-2 rounded-full border border-primary/20 bg-primary/5 px-3 py-1 text-xs font-semibold text-primary">
                <Sparkles className="h-3 w-3" />
                <span>Instructor Dashboard</span>
              </div>
              <h1 className="font-display text-4xl font-bold tracking-tight text-foreground sm:text-5xl">
                Manage your <span className="text-gradient">Teaching</span>
              </h1>
              <p className="mt-4 text-lg text-muted-foreground">
                Oversee your courses, track student engagement, and publish new material.
              </p>
            </div>

            {/* Floating Stats / Quick Actions */}
            <div className="relative hidden lg:block h-32 w-80 animate-fade-up delay-150">
               <div className="absolute top-0 right-10 animate-float delay-0 z-10">
                 <FloatingNode icon={<BookOpen className="h-5 w-5" />} label={`${oCourses.length} Courses`} />
               </div>
               <div className="absolute bottom-0 left-10 animate-float delay-500 z-10">
                 <FloatingNode icon={<Users className="h-5 w-5" />} label="Students" />
               </div>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-6 -mt-12 relative z-10 space-y-10 pb-20">

        {/* Actions Bar */}
        <div className="flex items-center justify-between bg-card/50 backdrop-blur-md p-4 rounded-2xl border border-border shadow-sm animate-fade-up delay-100">
           <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
             <BarChart3 className="h-4 w-4" />
             <span>Active Term: Fall 2024</span>
           </div>

           <button
            onClick={() => {
              setShowEduAiImport((prev) => {
                const next = !prev;
                if (next) {
                  ensureEduAiCourses();
                } else {
                  setEduAiError(null);
                }
                return next;
              });
            }}
            className="btn-primary shadow-lg shadow-primary/20"
          >
            {showEduAiImport ? (
              <>
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
                Close Import Panel
              </>
            ) : (
              <>
                <PlusCircle className="w-4 h-4" />
                Import New Course
              </>
            )}
          </button>
        </div>

        {/* EduAI Import Panel */}
        {showEduAiImport && (
          <div className="card-editorial p-8 space-y-6 animate-scale-in shadow-2xl ring-1 ring-border/50">
            <div className="flex flex-col sm:flex-row items-start justify-between gap-6 border-b border-border/50 pb-6">
              <div className="flex gap-4">
                <div className="h-12 w-12 rounded-2xl bg-primary/10 flex items-center justify-center flex-shrink-0">
                  <GraduationCap className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h2 className="font-display text-2xl font-bold text-foreground">Import from EduAI</h2>
                  <p className="text-muted-foreground mt-1">Select a course to sync its structure and enrollments.</p>
                </div>
              </div>
              <button
                type="button"
                onClick={fetchEduAiCourses}
                disabled={loadingEduAiCourses}
                className="btn-secondary text-sm"
              >
                <svg className={`w-4 h-4 ${loadingEduAiCourses ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182m0-4.991v4.99" />
                </svg>
                Refresh List
              </button>
            </div>

            {eduAiError && (
              <div className="flex items-center gap-3 rounded-xl bg-destructive/10 border border-destructive/20 px-4 py-3 text-sm text-destructive animate-fade-in">
                <svg className="w-4 h-4 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
                </svg>
                {eduAiError}
              </div>
            )}

            {loadingEduAiCourses ? (
              <div className="flex items-center justify-center py-20">
                <div className="flex flex-col items-center gap-3">
                  <svg className="w-8 h-8 text-muted-foreground animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth={4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                  </svg>
                  <p className="text-sm text-muted-foreground">Syncing course catalog...</p>
                </div>
              </div>
            ) : eduAiCourses.length === 0 ? (
              <div className="text-center py-12 bg-muted/20 rounded-xl border border-dashed border-border">
                <p className="text-muted-foreground">No pending courses found to import.</p>
              </div>
            ) : (
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {eduAiCourses.map((course, index) => {
                  const termYear = [course.term, course.year].filter(Boolean).join(' ');
                  return (
                    <div
                      key={course.id}
                      className="group flex flex-col rounded-xl border border-border bg-card p-5 transition-all hover:border-primary/50 hover:shadow-md animate-fade-up"
                      style={{ animationDelay: `${index * 50}ms` }}
                    >
                      <div className="flex-1 space-y-3">
                        <div className="flex items-center justify-between">
                           {course.code && <span className="tag tag-secondary font-mono text-xs">{course.code}</span>}
                           {termYear && <span className="text-xs text-muted-foreground">{termYear}</span>}
                        </div>
                        <h3 className="font-display text-lg font-bold text-foreground group-hover:text-primary transition-colors">
                          {course.name || 'Untitled Course'}
                        </h3>
                        {course.description && (
                          <p className="text-sm text-muted-foreground line-clamp-2">
                            {course.description}
                          </p>
                        )}
                      </div>
                      <button
                        type="button"
                        onClick={() => importEduAiCourse(course.id)}
                        disabled={importingExternalId === course.id}
                        className="btn-secondary w-full mt-5 group-hover:bg-primary group-hover:text-primary-foreground group-hover:border-primary"
                      >
                        {importingExternalId === course.id ? (
                          <>
                            <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                            </svg>
                            Importing...
                          </>
                        ) : (
                          <>
                            Import Course <ArrowRight className="w-4 h-4 ml-1" />
                          </>
                        )}
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {/* Course Grid Section */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-bold font-display text-foreground">Your Courses</h2>

            {/* Search/Filter placeholder (visual only for now) */}
