                <p className="text-muted-foreground mb-6">
                  You haven't imported any courses yet. Use the "Import New Course" button above to get started.
                </p>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {oCourses.map((c, index) => (
                <div
                  key={c.id}
                  role="button"
                  tabIndex={0}
                  onClick={() => navigate(`/instructor/courses/${c.id}`)}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter' || event.key === ' ') {
                      event.preventDefault();
                      navigate(`/instructor/courses/${c.id}`);
                    }
                  }}
                  className="group card-editorial flex flex-col cursor-pointer transition-all duration-300 hover:shadow-2xl hover:-translate-y-1 animate-fade-up overflow-hidden border-border/60 hover:border-primary/30"
                  style={{ animationDelay: `${150 + index * 50}ms` }}
                >
                  {/* Card Header with subtle pattern */}
                  <div className="relative h-32 bg-secondary/30 p-6 flex flex-col justify-between overflow-hidden">
                    <div className="absolute inset-0 opacity-10 bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-primary via-transparent to-transparent" />

                    <div className="flex justify-between items-start z-10">
                      <div className="w-10 h-10 rounded-xl bg-background/80 backdrop-blur-sm flex items-center justify-center text-primary shadow-sm group-hover:scale-110 transition-transform duration-300">
                        <BookOpen className="w-5 h-5" />
                      </div>

                      {c.externalSource === 'EDUAI' && (
                        <span className="tag tag-primary text-[10px] py-0.5 px-2 h-6">
                          EduAI Synced
                        </span>
                      )}
                    </div>
                  </div>

                  {/* Card Body */}
                  <div className="p-6 flex-1 flex flex-col">
                    <h3 className="font-display text-xl font-bold text-foreground mb-2 group-hover:text-primary transition-colors line-clamp-2">
                      {c.title}
                    </h3>

                    {c.description ? (
                       <p className="text-sm text-muted-foreground line-clamp-2 mb-4 flex-1">
                         {c.description}
                       </p>
                    ) : (
                       <p className="text-sm text-muted-foreground italic mb-4 flex-1 opacity-50">
                         No description provided
                       </p>
                    )}

                    {/* Stats Row (Mock for visual richness) */}
                    <div className="flex items-center gap-4 py-3 border-t border-border/50 text-xs text-muted-foreground mb-4">
                       <div className="flex items-center gap-1.5">
                         <Users className="w-3.5 h-3.5" />
                         <span>-- Students</span>
                       </div>
                       <div className="flex items-center gap-1.5">
                         <BarChart3 className="w-3.5 h-3.5" />
