                      <div
                        onClick={(event) => event.stopPropagation()}
                        onKeyDown={(event) => event.stopPropagation()}
                      >
                        <PublishStatusButton
                          isPublished={c.isPublished}
                          pending={publishingId === c.id}
                          onClick={() => {
                            if (publishingId === c.id) return;
                            togglePublish(c.id, c.isPublished);
                          }}
                        />
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

