cat <<EOF > app/routes/instructor.course.tsx
import type { FormEvent } from 'react';
import { useOptimistic, useRef, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router';
import Nav from '../components/Nav';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import { PublishStatusButton } from '../components/PublishStatusButton';
import api from '../lib/api';
import type { Course, Module } from '../lib/types';
import type { Route } from './+types/instructor.course';
import { requireClientUser } from '~/lib/client-auth';
import { 
  PlusCircle, 
  Box, 
  FileText, 
  ArrowRight, 
  Download,
  MoreVertical,
  LayoutGrid
} from 'lucide-react';

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const courseId = Number(params.courseId);
  if (!Number.isFinite(courseId)) {
    throw new Response('Invalid course id', { status: 400 });
  }

  const [course, modules] = await Promise.all([
    api.courseById(courseId) as Promise<Course>,
    api.modulesForCourse(courseId) as Promise<Module[]>,
  ]);

  return { course, modules };
}

export default function InstructorCourseModules({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const { courseId } = useParams();
  const numericCourseId = courseId ? Number(courseId) : null;
  const { course, modules: initialModules } = loaderData;
  const [modules, setModules] = useState<Module[]>(initialModules);
  const [title, setTitle] = useState('');
  const [creating, setCreating] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [availableCourses, setAvailableCourses] = useState<Course[]>([]);
  const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
  const [sourceModules, setSourceModules] = useState<Module[]>([]);
  const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
  const [loadingSourceModules, setLoadingSourceModules] = useState(false);
  const [selectedModuleIds, setSelectedModuleIds] = useState<Set<number>>(new Set());
  const [importing, setImporting] = useState(false);
  const [publishingId, setPublishingId] = useState<number | null>(null);
  const modulesRequestIdRef = useRef(0);

  const [oModules, addModuleOpt] = useOptimistic(
    modules,
    (state, patch: (items: Module[]) => Module[]) => patch(state),
  );

  // Adjust state during render when loader data changes
  const [prevInitialModules, setPrevInitialModules] = useState(initialModules);
  if (initialModules !== prevInitialModules) {
    setPrevInitialModules(initialModules);
    setModules(initialModules);
  }

  const refreshModules = async () => {
    if (!numericCourseId) return;
    try {
      const modulesData = await api.modulesForCourse(numericCourseId);
      setModules(modulesData);
    } catch (error) {
      console.error('Failed to refresh modules', error);
    }
  };

  const ensureSourceCoursesLoaded = () => {
    if (availableCourses.length > 0) return;
    setLoadingSourceCourses(true);
    api
      .listCourses()
      .then((data: Course[]) => {
        const nextCourses = numericCourseId
          ? data.filter((course: Course) => course.id !== numericCourseId)
          : data;
        setAvailableCourses(nextCourses);
      })
      .catch((error) => console.error('Failed to load courses', error))
      .finally(() => setLoadingSourceCourses(false));
  };

  const handleSourceCourseSelection = async (nextCourseId: number | null) => {
    const requestId = ++modulesRequestIdRef.current;
    setSelectedSourceCourseId(nextCourseId);
    setSourceModules([]);
    setSelectedModuleIds(new Set());

    if (nextCourseId == null) {
      setLoadingSourceModules(false);
      return;
    }

    setLoadingSourceModules(true);
    try {
      const data = await api.modulesForCourse(nextCourseId);
      if (modulesRequestIdRef.current === requestId) {
        setSourceModules(data);
      }
    } catch (error) {
      if (modulesRequestIdRef.current === requestId) {
        console.error('Failed to load modules for course', error);
        setSourceModules([]);
      }
    } finally {
      if (modulesRequestIdRef.current === requestId) {
        setLoadingSourceModules(false);
      }
    }
  };

  const onCreateModule = async (event: FormEvent) => {
    event.preventDefault();
    if (!numericCourseId || !title.trim()) return;
    setCreating(true);
    try {
      await api.createModule(numericCourseId, { title: title.trim() });
      setTitle('');
      await refreshModules();
    } catch (error) {
      console.error('Failed to create module', error);
    } finally {
      setCreating(false);
    }
  };

  const toggleModuleSelection = (moduleId: number) => {
    setSelectedModuleIds((prev) => {
      const next = new Set(prev);
      if (next.has(moduleId)) next.delete(moduleId);
      else next.add(moduleId);
      return next;
    });
  };

  const onImport = async () => {
    if (!numericCourseId || selectedSourceCourseId == null || selectedModuleIds.size === 0) return;
    setImporting(true);
    try {
      await api.importIntoCourse(numericCourseId, {
        sourceCourseId: selectedSourceCourseId,
        moduleIds: Array.from(selectedModuleIds),
      });
      setShowImport(false);
      await handleSourceCourseSelection(null);
      await refreshModules();
    } catch (error) {
      console.error('Import failed', error);
    } finally {
      setImporting(false);
    }
  };


  const togglePublish = async (moduleId: number, currentlyPublished: boolean) => {
    addModuleOpt((items) =>
      items.map((m) => (m.id === moduleId ? { ...m, isPublished: !currentlyPublished } : m)),
    );
    setPublishingId(moduleId);

    try {
      const updated = currentlyPublished
        ? await api.unpublishModule(moduleId)
        : await api.publishModule(moduleId);
      setModules((prev) => prev.map((m) => (m.id === moduleId ? updated : m)));
    } catch (error) {
      console.error('Failed to toggle publish status', error);
      setModules((prev) =>
        prev.map((m) => (m.id === moduleId ? { ...m, isPublished: currentlyPublished } : m)),
      );
    } finally {
      setPublishingId((current) => (current === moduleId ? null : current));
    }
  };

  return (
    <div className="min-h-dvh bg-background">
      <Nav />

      {/* Header Section */}
      <div className="relative border-b border-border/40 bg-muted/20 pb-12 pt-8">
         <div className="absolute inset-0 dots-pattern opacity-30" />

         <div className="container mx-auto px-6 relative z-10">
            <Breadcrumb className="mb-6">
              <BreadcrumbList>
                <BreadcrumbItem>
                  <BreadcrumbLink asChild>
                    <Link to="/instructor" className="hover:text-primary transition-colors">Teaching</Link>
                  </BreadcrumbLink>
                </BreadcrumbItem>
                <BreadcrumbSeparator />
                <BreadcrumbItem>
                  <BreadcrumbPage>{course?.title || 'Course'}</BreadcrumbPage>
                </BreadcrumbItem>
              </BreadcrumbList>
            </Breadcrumb>

            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <h1 className="font-display text-3xl font-bold tracking-tight text-foreground sm:text-4xl">
                  {course?.title || 'Course Modules'}
                </h1>
                {course?.description && (
                  <p className="mt-2 text-muted-foreground max-w-2xl">
                    {course.description}
                  </p>
                )}
              </div>

              <div className="flex items-center gap-3">
                 <button
                   onClick={() => {
                     if (!showImport) {
                       ensureSourceCoursesLoaded();
                     } else {
                       void handleSourceCourseSelection(null);
                     }
                     setShowImport((prev) => !prev);
                   }}
                   className="btn-secondary"
                 >
                   {showImport ? (
                     <>Close Import</>
                   ) : (
                     <>
                       <Download className="w-4 h-4 mr-2" />
                       Import Content
                     </>
                   )}
                 </button>
              </div>
            </div>
         </div>
      </div>

      <div className="container mx-auto px-6 -mt-8 relative z-10 space-y-8 pb-20">

          {/* Quick Stats or Actions Bar */}
          <div className="bg-card/50 backdrop-blur-md p-1 rounded-2xl border border-border shadow-sm animate-fade-up">
            <form onSubmit={onCreateModule} className="flex gap-2">
              <div className="relative flex-1">
                <LayoutGrid className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <input
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Create a new module..."
                  className="w-full bg-transparent border-none py-3 pl-10 pr-4 focus:ring-0 text-foreground placeholder:text-muted-foreground/70"
                />
              </div>
              <button
                disabled={creating || !title.trim()}
                className="btn-primary m-1"
              >
                {creating ? 'Creating...' : <><PlusCircle className="w-4 h-4 mr-2" /> Add Module</>}
              </button>
            </form>
          </div>

          {showImport && (
            <div className="card-editorial p-6 space-y-5 animate-scale-in ring-1 ring-primary/20">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-bold font-display">Import Modules</h3>
                <span className="text-xs text-muted-foreground bg-muted px-2 py-1 rounded-full">Step 1: Select Source</span>
              </div>

              <div className="grid gap-6 md:grid-cols-2">
                <div>
                  <label className="block text-sm font-medium mb-2 text-foreground">Source Course</label>
                  <select
                    value={selectedSourceCourseId ?? ''}
                    onChange={(e) => {
                      const nextValue = e.target.value ? Number(e.target.value) : null;
                      void handleSourceCourseSelection(nextValue);
                    }}
                    className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm focus:border-primary focus:ring-1 focus:ring-primary"
                  >
                    <option value="">Select a course...</option>
                    {availableCourses.map((course) => (
                      <option key={course.id} value={course.id}>
                        {course.title}
                      </option>
                    ))}
                  </select>
                  {loadingSourceCourses && <p className="mt-2 text-xs text-muted-foreground animate-pulse">Loading courses...</p>}
                  {!loadingSourceCourses && availableCourses.length === 0 && (
                    <p className="mt-2 text-xs text-destructive">No other courses available.</p>
                  )}
                </div>

                <div className="border-l border-border pl-6">
                  {selectedSourceCourseId == null ? (
                    <div className="h-full flex items-center justify-center text-muted-foreground text-sm italic">
                      Select a course to view modules
                    </div>
                  ) : loadingSourceModules ? (
                    <div className="h-full flex items-center justify-center text-muted-foreground text-sm animate-pulse">
                      Loading content...
                    </div>
                  ) : sourceModules.length === 0 ? (
                    <div className="h-full flex items-center justify-center text-muted-foreground text-sm italic">
                      No content found in selected course
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <p className="text-sm font-medium">Select Content to Import:</p>
                      <div className="max-h-60 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                        {sourceModules.map((module) => (
                          <label
                            key={module.id}
                            className={`flex items-start gap-3 p-3 rounded-lg border cursor-pointer transition-all ${
                              selectedModuleIds.has(module.id)
                                ? 'border-primary bg-primary/5'
                                : 'border-border hover:border-primary/30'
                            }`}
                          >
                            <input
                              type="checkbox"
                              className="mt-1 rounded border-gray-300 text-primary focus:ring-primary"
                              checked={selectedModuleIds.has(module.id)}
                              onChange={() => toggleModuleSelection(module.id)}
                            />
                            <div>
                              <div className="font-medium text-sm">{module.title}</div>
                              {module.description && (
                                <div className="text-xs text-muted-foreground line-clamp-1">{module.description}</div>
                              )}
                            </div>
                          </label>
                        ))}
                      </div>
                      <button
                        onClick={onImport}
                        disabled={importing || selectedModuleIds.size === 0}
                        className="btn-primary w-full"
                      >
                        {importing ? 'Importing...' : \`Import \${selectedModuleIds.size} Modules\`}
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}

          {oModules.length === 0 ? (
            <div className="text-center py-20 opacity-50">
               <Box className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
               <p className="text-muted-foreground">This course is empty. Create your first module above.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-4">
              {oModules.map((m, idx) => {
                const canPublish = course?.isPublished;
                const blocked = !m.isPublished && !canPublish;
                const tooltipMessage = blocked
                  ? \`Publish \${m.title} after publishing \${course?.title ?? 'the parent course'}.\`
                  : null;
                const busy = publishingId === m.id;

                return (
                  <div
                    key={m.id}
                    className="group flex flex-col sm:flex-row sm:items-center justify-between gap-4 p-5 rounded-xl border border-border bg-card hover:border-primary/50 transition-all hover:shadow-md animate-fade-up"
                    style={{ animationDelay: \`\${idx * 50}ms\` }}
                    onClick={() => navigate(\`/instructor/module/\${m.id}\`)}
                  >
                    <div className="flex items-start gap-4">
                       <div className="h-10 w-10 rounded-lg bg-secondary flex items-center justify-center text-muted-foreground font-mono text-sm group-hover:bg-primary group-hover:text-primary-foreground transition-colors">
                         {idx + 1}
                       </div>
                       <div>
                          <h3 className="font-display font-semibold text-lg text-foreground group-hover:text-primary transition-colors">
                            {m.title}
                          </h3>
                          {m.description ? (
                             <p className="text-sm text-muted-foreground line-clamp-1">{m.description}</p>
                          ) : (
                             <p className="text-xs text-muted-foreground italic opacity-50">No description</p>
                          )}
                       </div>
                    </div>

                    <div className="flex items-center gap-4 pl-14 sm:pl-0 border-t sm:border-t-0 pt-4 sm:pt-0 border-border/50">
                      <div onClick={(e) => e.stopPropagation()} onKeyDown={(e) => e.stopPropagation()}>
                        <PublishStatusButton
                          isPublished={m.isPublished}
                          pending={busy}
                          blockedReason={tooltipMessage}
                          onClick={() => {
                            if (busy || blocked) return;
                            togglePublish(m.id, m.isPublished);
                          }}
                        />
                      </div>

                      <div className="h-8 w-[1px] bg-border hidden sm:block" />

                      <button className="btn-icon text-muted-foreground hover:text-foreground">
                        <ArrowRight className="w-5 h-5" />
