                <BreadcrumbItem>
                  <BreadcrumbLink asChild>
                    <Link to="/instructor" className="hover:text-primary transition-colors">Teaching</Link>
                  </BreadcrumbLink>
                </BreadcrumbItem>
                <BreadcrumbSeparator />
                <BreadcrumbItem>
                  <BreadcrumbPage>{course?.title || 'Course'}</BreadcrumbPage>
                </BreadcrumbItem>
              </BreadcrumbList>
            </Breadcrumb>

            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <h1 className="font-display text-3xl font-bold tracking-tight text-foreground sm:text-4xl">
                  {course?.title || 'Course Modules'}
                </h1>
                {course?.description && (
                  <p className="mt-2 text-muted-foreground max-w-2xl">
                    {course.description}
                  </p>
                )}
              </div>

              <div className="flex items-center gap-3">
                 <button
                   onClick={() => {
                     if (!showImport) {
                       ensureSourceCoursesLoaded();
                     } else {
                       void handleSourceCourseSelection(null);
                     }
                     setShowImport((prev) => !prev);
                   }}
                   className="btn-secondary"
                 >
                   {showImport ? (
                     <>Close Import</>
                   ) : (
                     <>
                       <Download className="w-4 h-4 mr-2" />
                       Import Content
                     </>
                   )}
                 </button>
              </div>
            </div>
         </div>
      </div>

      <div className="container mx-auto px-6 -mt-8 relative z-10 space-y-8 pb-20">

          {/* Quick Stats or Actions Bar */}
          <div className="bg-card/50 backdrop-blur-md p-1 rounded-2xl border border-border shadow-sm animate-fade-up">
            <form onSubmit={onCreateModule} className="flex gap-2">
              <div className="relative flex-1">
                <LayoutGrid className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <input
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Create a new module..."
                  className="w-full bg-transparent border-none py-3 pl-10 pr-4 focus:ring-0 text-foreground placeholder:text-muted-foreground/70"
                />
              </div>
              <button
                disabled={creating || !title.trim()}
                className="btn-primary m-1"
              >
                {creating ? 'Creating...' : <><PlusCircle className="w-4 h-4 mr-2" /> Add Module</>}
              </button>
            </form>
          </div>

          {showImport && (
            <div className="card-editorial p-6 space-y-5 animate-scale-in ring-1 ring-primary/20">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-bold font-display">Import Modules</h3>
                <span className="text-xs text-muted-foreground bg-muted px-2 py-1 rounded-full">Step 1: Select Source</span>
              </div>

              <div className="grid gap-6 md:grid-cols-2">
                <div>
