                    onChange={(e) => {
                      const nextValue = e.target.value ? Number(e.target.value) : null;
                      void handleSourceCourseSelection(nextValue);
                    }}
                    className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm focus:border-primary focus:ring-1 focus:ring-primary"
                  >
                    <option value="">Select a course...</option>
                    {availableCourses.map((course) => (
                      <option key={course.id} value={course.id}>
                        {course.title}
                      </option>
                    ))}
                  </select>
                  {loadingSourceCourses && <p className="mt-2 text-xs text-muted-foreground animate-pulse">Loading courses...</p>}
                  {!loadingSourceCourses && availableCourses.length === 0 && (
