              const percent = progress && progress.total > 0 
                ? Math.round((progress.completed / progress.total) * 100) 
                : 0;

              return (
                <div
                  key={lesson.id}
                  onClick={() => navigate(`/student/lesson/${lesson.id}`)}
                  className="group relative flex flex-col bg-card border border-border rounded-2xl p-6 hover:shadow-xl hover:-translate-y-1 transition-all duration-300 cursor-pointer overflow-hidden animate-fade-up"
                  style={{ animationDelay: `${index * 50}ms` }}
