63.   }
64. 
65.   const [lesson, activities] = await Promise.all([
66.     api.lessonById(lessonId) as Promise<Lesson>,
67.     api.activitiesForLesson(lessonId) as Promise<Activity[]>,
68.   ]);
69. 
70.   let module: ModuleDetail | null = null;
