90.   );
91. 
92.   const [updatingTopicsFor, setUpdatingTopicsFor] = useState<number | null>(null);
93.   const [updatingModesFor, setUpdatingModesFor] = useState<number | null>(null);
94. 
95.   const [showAddPanel, setShowAddPanel] = useState(false);
96. 
97.   const [editingActivityId, setEditingActivityId] = useState<number | null>(null);
98.   const [savingActivityId, setSavingActivityId] = useState<number | null>(null);
99.   const [deletingActivityId, setDeletingActivityId] = useState<number | null>(null);
100.   const [editError, setEditError] = useState<string | null>(null);
101. 
102.   const courseOfferingId = lesson?.courseOfferingId ?? null;
