132.       if (current !== activityId) {
133.         return current;
134.       }
135.       shouldClear = true;
136.       return null;
137.     });
138.     if (shouldClear) {
139.       if (topicSavingTimeoutRef.current) {
140.         clearTimeout(topicSavingTimeoutRef.current);
141.         topicSavingTimeoutRef.current = null;
142.       }
143.       setShowTopicSaving(false);
144.     }
145.   };
