148.     setUpdatingModesFor(activityId);
149.     setShowModeSaving(false);
150.     if (modeSavingTimeoutRef.current) {
151.       clearTimeout(modeSavingTimeoutRef.current);
152.     }
153.     modeSavingTimeoutRef.current = setTimeout(() => setShowModeSaving(true), 300);
154.   };
