209.       );
210.       cancelEditingActivity();
211.     } catch (error) {
212.       console.error('Failed to update activity', error);
213.       setEditError('Could not save activity. Please try again.');
214.     } finally {
215.       setSavingActivityId((current) => (current === activityId ? null : current));
216.     }
217.   };
