231.       if (topicSavingTimeoutRef.current) {
232.         clearTimeout(topicSavingTimeoutRef.current);
233.         topicSavingTimeoutRef.current = null;
234.       }
235.       if (modeSavingTimeoutRef.current) {
236.         clearTimeout(modeSavingTimeoutRef.current);
237.         modeSavingTimeoutRef.current = null;
238.       }
239.     };
