277.     const newGuide = mode === 'guide' ? enabled : activity.enableGuideMode;
278.     const newCustom = mode === 'custom' ? enabled : activity.enableCustomMode;
279. 
280.     if (!newTeach && !newGuide && !newCustom) {
281.       alert('At least one AI mode must be enabled');
282.       return;
283.     }
