285.     // Optimistic UI via useOptimistic
286.     addActivityOpt((items) =>
287.       items.map((a) =>
288.         a.id === activityId
289.           ? {
290.               ...a,
291.               enableTeachMode: newTeach,
292.               enableGuideMode: newGuide,
293.               enableCustomMode: newCustom,
294.               customPrompt: mode === 'custom' && !enabled ? null : a.customPrompt,
295.             }
296.           : a,
297.       ),
298.     );
299.     if (mode === 'custom' && !enabled) {
