                       const isSavingPrompt = savingPromptId === activity.id;
                       const isPromptSaved =
                         promptSaved[activity.id] ??
                         Boolean(activity.enableCustomMode && activity.customPrompt);
                       const promptError = promptErrors[activity.id];
                       return (
