                                     onClick={() => handleCustomPromptSave(activity)}
                                     disabled={isSavingPrompt}
                                     className="btn-primary text-xs py-2"
                                   >
                                     {isSavingPrompt ? 'Saving…' : isPromptSaved ? 'Saved' : 'Save prompt'}
                                   </button>
                                   {promptError && (
