1. import { useCallback, useMemo, useRef, useState } from 'react';
2. import { Link } from 'react-router';
3. import Nav from '../components/Nav';
4. import { ProgressBar } from '../components/ProgressBar';
5. import StudentActivityFeedbackCard from '../components/StudentActivityFeedbackCard';
6. import StudentAiChat, { type StudentAiChatHandle } from '../components/StudentAiChat';
7. import {
8.   Breadcrumb,
9.   BreadcrumbList,
10.   BreadcrumbItem,
11.   BreadcrumbLink,
12.   BreadcrumbPage,
13.   BreadcrumbSeparator,
14. } from '../components/ui/breadcrumb';
15. import api from '../lib/api';
16. import type { Activity, Course, Lesson, ModuleDetail } from '../lib/types';
17. import type { Route } from './+types/student.list';
18. import { requireClientUser } from '~/lib/client-auth';
19. import { useLocalUser } from '~/hooks/useLocalUser';
20. 
21. type StudentFeedbackState = {
22.   rating: number | null;
23.   note: string;
24.   promptShown: boolean;
25.   promptVisible: boolean;
26.   submitted: boolean;
27.   dismissed: boolean;
28.   saving: boolean;
29.   error: string | null;
30. };
31. 
32. type FeedbackApi = typeof api & {
33.   submitActivityFeedback?: (
34.     activityId: number,
35.     payload: { rating: number; note?: string },
36.   ) => Promise<{ ok?: boolean }>;
37. };
38. 
39. function createFeedbackState(): StudentFeedbackState {
40.   return {
41.     rating: null,
42.     note: '',
43.     promptShown: false,
44.     promptVisible: false,
45.     submitted: false,
46.     dismissed: false,
47.     saving: false,
48.     error: null,
49.   };
50. }
51. 
52. export async function clientLoader({ params }: Route.ClientLoaderArgs) {
53.   await requireClientUser('STUDENT');
54.   const lessonId = Number(params.lessonId);
55.   if (!Number.isFinite(lessonId)) {
56.     throw new Response('Invalid lesson id', { status: 400 });
57.   }
58. 
59.   const [lesson, activities] = await Promise.all([
60.     api.lessonById(lessonId) as Promise<Lesson>,
61.     api.activitiesForLesson(lessonId) as Promise<Activity[]>,
62.   ]);
63. 
64.   let module: ModuleDetail | null = null;
65.   let course: Course | null = null;
66.   if (lesson.moduleId) {
67.     module = (await api.moduleById(lesson.moduleId)) as ModuleDetail;
68.     if (module?.courseOfferingId) {
69.       course = (await api.courseById(module.courseOfferingId)) as Course;
70.     }
71.   }
72. 
73.   return { course, module, lesson, activities };
74. }
75. 
76. export default function StudentLessonPlayer({ loaderData }: Route.ComponentProps) {
77.   const { user } = useLocalUser();
78.   const { course, module, lesson, activities } = loaderData;
79.   const [orderedActivities, setOrderedActivities] = useState<Activity[]>(activities ?? []);
80.   const [idx, setIdx] = useState(0);
81.   const [mcq, setMcq] = useState<number | null>(null);
82.   const [text, setText] = useState('');
83.   const [submitting, setSubmitting] = useState(false);
84.   const [result, setResult] = useState<string | null>(null);
85.   const [wasCorrect, setWasCorrect] = useState(false);
86.   const [prevActivityId, setPrevActivityId] = useState<number | null>(null);
87. 
88.   // Pre-chat context for AI guidance
89.   const [showKnowledgeModal, setShowKnowledgeModal] = useState(false);
90.   const [tempKnowledgeLevel, setTempKnowledgeLevel] = useState('');
91.   const [knowledgeLevels, setKnowledgeLevels] = useState<Record<number, string>>({});
92.   const [topicSelection, setTopicSelection] = useState<Record<number, number>>({});
93.   const [feedbackByActivity, setFeedbackByActivity] = useState<Record<number, StudentFeedbackState>>({});
94.   const chatRef = useRef<StudentAiChatHandle>(null);
95. 
96.   // Adjust state during render when loader data changes
97.   const [prevActivities, setPrevActivities] = useState(activities);
98.   if (activities !== prevActivities) {
99.     setPrevActivities(activities);
100.     setOrderedActivities(activities ?? []);
101.   }
102. 
103.   const activity = orderedActivities[idx];
104.   const canNext = idx < orderedActivities.length - 1;
105.   const canPrev = idx > 0;
106. 
107.   const questionChunks = useMemo(
108.     () => (activity?.question || '').split(/\n/),
109.     [activity?.question],
110.   );
111. 
112.   const currentKnowledgeLevel = activity ? knowledgeLevels[activity.id] ?? null : null;
113.   const currentTopicId = activity
114.     ? topicSelection[activity.id] ?? activity.mainTopic?.id ?? null
115.     : null;
116.   const currentFeedback = activity ? feedbackByActivity[activity.id] ?? createFeedbackState() : createFeedbackState();
117.   const studentAnswer = activity
118.     ? activity.type === 'MCQ'
119.       ? mcq
120.       : text
121.     : null;
122.   const isUserReady = Boolean(user);
123. 
124.   const currentActivityId = activity?.id ?? null;
125.   if (currentActivityId !== prevActivityId) {
126.     setPrevActivityId(currentActivityId);
127.     setWasCorrect(false);
128.     setResult(null);
129.     setTempKnowledgeLevel('');
130.     setShowKnowledgeModal(false);
131.     setMcq(null);
132.     setText('');
133.   }
134. 
135.   const submit = async () => {
136.     if (!activity || !user) return;
137.     setSubmitting(true);
138.     try {
139.       const payload: any = { userId: user.id };
140.       if (activity.type === 'MCQ') payload.answerOption = mcq;
141.       else payload.answerText = text;
142.       const res = await api.submitAnswer(activity.id, payload);
143.       setResult(res.isCorrect ? 'Correct!' : 'Not quite. Keep going!');
144. 
145.       setOrderedActivities((prev) =>
146.         prev.map((a, i) =>
147.           i === idx ? { ...a, completionStatus: res.isCorrect ? ('correct' as const) : undefined } : a
148.         )
149.       );
150. 
151.       if (res.isCorrect) {
152.         setWasCorrect(true);
153.         chatRef.current?.pushGuideMessage(
154.           res.message || 'Great job! Proceed when you are ready for the next question.',
155.         );
156.       } else {
157.         setWasCorrect(false);
158.       }
159. 
160.       setFeedbackByActivity((prev) => {
161.         const current = prev[activity.id] ?? createFeedbackState();
162.         if (
163.           current.promptShown ||
164.           current.submitted ||
165.           current.dismissed ||
166.           res.feedbackRequired === false ||
167.           res.feedbackAlreadySubmitted
168.         ) {
169.           return prev;
170.         }
171.         return {
172.           ...prev,
173.           [activity.id]: {
174.             ...current,
175.             promptShown: true,
176.             promptVisible: true,
177.             error: null,
178.           },
179.         };
180.       });
181.     } catch (e) {
182.       setResult('There was a problem submitting.');
183.       setWasCorrect(false);
184.     } finally {
185.       setSubmitting(false);
186.     }
187.   };
188. 
189.   const resetForNavigation = useCallback(() => {
190.     setMcq(null);
191.     setText('');
192.     setResult(null);
193.     setWasCorrect(false);
194.     setTempKnowledgeLevel('');
195.   }, []);
196. 
197.   const handleRequestKnowledgeLevel = useCallback(() => {
198.     setTempKnowledgeLevel('');
199.     setShowKnowledgeModal(true);
200.   }, []);
201. 
202.   const handleAdjustKnowledgeLevel = useCallback(() => {
203.     setTempKnowledgeLevel(currentKnowledgeLevel ?? '');
204.     setShowKnowledgeModal(true);
205.   }, [currentKnowledgeLevel]);
206. 
207.   const handleTopicSelect = useCallback(
208.     (topicId: number) => {
209.       if (!activity) return;
210.       setTopicSelection((prev) => ({ ...prev, [activity.id]: topicId }));
211.     },
212.     [activity],
213.   );
214. 
215.   const handleGuideMe = useCallback(() => {
216.     if (!activity || wasCorrect) return;
217.     chatRef.current?.sendGuidePrompt();
218.   }, [activity, wasCorrect]);
219. 
220.   const updateFeedbackState = useCallback(
221.     (updater: (current: StudentFeedbackState) => StudentFeedbackState) => {
222.       if (!activity) return;
223.       setFeedbackByActivity((prev) => ({
224.         ...prev,
225.         [activity.id]: updater(prev[activity.id] ?? createFeedbackState()),
226.       }));
227.     },
228.     [activity],
229.   );
230. 
231.   const handleFeedbackRating = useCallback(
232.     (rating: number) => {
233.       updateFeedbackState((current) => ({
234.         ...current,
235.         rating,
236.         error: null,
237.       }));
238.     },
239.     [updateFeedbackState],
240.   );
241. 
242.   const handleFeedbackNote = useCallback(
243.     (note: string) => {
244.       updateFeedbackState((current) => ({
245.         ...current,
246.         note,
247.       }));
248.     },
249.     [updateFeedbackState],
250.   );
251. 
252.   const handleDismissFeedback = useCallback(() => {
253.     updateFeedbackState((current) => ({
254.       ...current,
255.       promptVisible: false,
256.       dismissed: true,
257.       error: null,
258.     }));
259.   }, [updateFeedbackState]);
260. 
261.   const handleSubmitFeedback = useCallback(async () => {
262.     if (!activity || !currentFeedback.rating) return;
263. 
264.     updateFeedbackState((current) => ({
265.       ...current,
266.       saving: true,
267.       error: null,
268.     }));
269. 
270.     try {
271.       const feedbackApi = api as FeedbackApi;
272.       if (typeof feedbackApi.submitActivityFeedback !== 'function') {
273.         throw new Error('Feedback service not available');
274.       }
275. 
276.       await feedbackApi.submitActivityFeedback(activity.id, {
277.         rating: currentFeedback.rating,
278.         note: currentFeedback.note.trim() || undefined,
279.       });
280. 
281.       updateFeedbackState((current) => ({
282.         ...current,
283.         saving: false,
284.         submitted: true,
285.         promptVisible: false,
286.         dismissed: false,
287.         error: null,
288.       }));
289.     } catch (error) {
290.       updateFeedbackState((current) => ({
291.         ...current,
292.         saving: false,
293.         error: 'Could not save feedback right now. Please try again.',
294.       }));
295.     }
296.   }, [activity, currentFeedback.note, currentFeedback.rating, updateFeedbackState]);
297. 
298.   const handleConfirmKnowledge = () => {
299.     if (!activity || !tempKnowledgeLevel) {
300.       return;
301.     }
302.     setKnowledgeLevels((prev) => ({ ...prev, [activity.id]: tempKnowledgeLevel }));
303.     setShowKnowledgeModal(false);
304.   };
305. 
306.   const handleCancelKnowledge = () => {
307.     setShowKnowledgeModal(false);
308.   };
309. 
310.   const topicOptions = activity
311.     ? [
312.         ...(activity.mainTopic ? [{ label: activity.mainTopic.name, value: activity.mainTopic.id }] : []),
313.         ...activity.secondaryTopics.map((topic) => ({ label: topic.name, value: topic.id })),
314.       ]
315.     : [];
316. 
317.   return (
318.     <div className="min-h-dvh bg-background">
319.       <Nav />
320.       
321.       {/* Background decoration */}
322.       <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
323.         <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-primary/3 rounded-full blur-3xl -translate-y-1/2 translate-x-1/3" />
324.         <div className="absolute bottom-0 left-0 w-[600px] h-[600px] bg-accent/5 rounded-full blur-3xl translate-y-1/2 -translate-x-1/3" />
325.       </div>
326.       
327.       <div className="container mx-auto px-6 py-8">
328.         {/* Breadcrumb */}
329.         <Breadcrumb className="mb-6 animate-fade-in" data-tour="student-lesson-breadcrumb">
330.           <BreadcrumbList>
331.             <BreadcrumbItem>
332.               <BreadcrumbLink asChild>
333.                 <Link to="/student" className="text-muted-foreground hover:text-foreground transition-colors">
334.                   My Courses
335.                 </Link>
336.               </BreadcrumbLink>
337.             </BreadcrumbItem>
338.             <BreadcrumbSeparator className="text-border">/</BreadcrumbSeparator>
339.             <BreadcrumbItem>
340.               {course && module ? (
341.                 <BreadcrumbLink asChild>
342.                   <Link to={`/student/courses/${module.courseOfferingId}`} className="text-muted-foreground hover:text-foreground transition-colors">
343.                     {course.title}
344.                   </Link>
345.                 </BreadcrumbLink>
346.               ) : (
347.                 <BreadcrumbPage>Course</BreadcrumbPage>
348.               )}
349.             </BreadcrumbItem>
350.             <BreadcrumbSeparator className="text-border">/</BreadcrumbSeparator>
351.             <BreadcrumbItem>
352.               {module && lesson ? (
353.                 <BreadcrumbLink asChild>
354.                   <Link to={`/student/module/${lesson.moduleId}`} className="text-muted-foreground hover:text-foreground transition-colors">
355.                     {module.title}
356.                   </Link>
357.                 </BreadcrumbLink>
358.               ) : (
359.                 <BreadcrumbPage>Module</BreadcrumbPage>
