                <BreadcrumbSeparator />
                <BreadcrumbItem>
                  {course && module ? (
                    <BreadcrumbLink asChild>
                      <Link to={`/instructor/courses/${module.courseOfferingId}`} className="hover:text-primary transition-colors">{course.title}</Link>
                    </BreadcrumbLink>
