                    <BreadcrumbPage>Course</BreadcrumbPage>
                  )}
                </BreadcrumbItem>
                <BreadcrumbSeparator />
                <BreadcrumbItem>
                  {module && lesson ? (
                    <BreadcrumbLink asChild>
                      <Link to={`/instructor/module/${lesson.moduleId}`} className="hover:text-primary transition-colors">{module.title}</Link>
                    </BreadcrumbLink>
                  ) : (
                    <BreadcrumbPage>Module</BreadcrumbPage>
                  )}
                </BreadcrumbItem>
                <BreadcrumbSeparator />
                <BreadcrumbItem>
                  <BreadcrumbPage>{lesson?.title || 'Lesson'}</BreadcrumbPage>
                </BreadcrumbItem>
              </BreadcrumbList>
            </Breadcrumb>

            <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-8">
              <div className="max-w-3xl">
                <div className="flex items-center gap-3 mb-3">
                   <div className="h-12 w-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary">
                      <BookOpen className="h-6 w-6" />
                   </div>
                   <h1 className="font-display text-3xl sm:text-4xl font-bold tracking-tight text-foreground">
                     {lesson?.title || 'Lesson Builder'}
                   </h1>
                </div>
                <p className="text-muted-foreground text-lg leading-relaxed max-w-2xl">
                  {oActivities.length} activities in this lesson.
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="container mx-auto px-6 -mt-8 relative z-10 pb-20">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">

              {/* Main Content: Activities List */}
              <div className="lg:col-span-2 space-y-6">
                <div className="card-editorial p-6 animate-fade-up">
                  <div className="flex items-center justify-between mb-6">
                    <h3 className="font-display text-xl font-bold text-foreground">Activities</h3>
                    <span className="text-sm text-muted-foreground bg-secondary px-2 py-1 rounded-md">
                      {oActivities.length} Items
                    </span>
                  </div>

                  {oActivities.length === 0 ? (
                    <div className="text-center py-12 border-2 border-dashed border-border rounded-xl">
                      <p className="text-muted-foreground">No activities yet. Add some below!</p>
                    </div>
                  ) : (
                    <ul className="space-y-6">
                      {oActivities.map((activity, i) => {
                        const isUpdatingTopics = updatingTopicsFor === activity.id;
                        const isUpdatingModes = updatingModesFor === activity.id;
                        const mainTopicId = activity.mainTopic?.id ?? '';
                        const secondaryIds = new Set(activity.secondaryTopics.map((item) => item.id));
                        const isEditing = editingActivityId === activity.id;
                        const isSaving = savingActivityId === activity.id;
                        const isDeleting = deletingActivityId === activity.id;
                        const isCustomEnabled = activity.enableCustomMode;
                        const promptDraft = promptDrafts[activity.id] ?? activity.customPrompt ?? '';
                        const isSavingPrompt = savingPromptId === activity.id;
                        const isPromptSaved =
                          promptSaved[activity.id] ??
                          Boolean(activity.enableCustomMode && activity.customPrompt);
                        const promptError = promptErrors[activity.id];

                        return (
                          <li
                            key={activity.id}
                            className="group relative p-6 rounded-2xl border border-border bg-card hover:shadow-lg transition-all duration-300 space-y-5"
                          >
                            <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                              {!isEditing && (
                                <>
                                  <button
                                    type="button"
                                    onClick={() => beginEditingActivity(activity)}
                                    className="p-2 rounded-lg bg-secondary text-secondary-foreground hover:bg-primary hover:text-primary-foreground transition-colors"
                                    disabled={isDeleting}
                                    title="Edit"
                                  >
                                    <Edit2 className="w-4 h-4" />
                                  </button>
                                  <button
                                    type="button"
                                    onClick={() => handleDeleteActivity(activity.id)}
                                    className="p-2 rounded-lg bg-destructive/10 text-destructive hover:bg-destructive hover:text-destructive-foreground transition-colors"
                                    disabled={isDeleting}
                                    title="Delete"
                                  >
                                    {isDeleting ? <span className="animate-spin">...</span> : <Trash2 className="w-4 h-4" />}
                                  </button>
                                </>
                              )}
                            </div>

                            <div className="flex items-start gap-4">
                              <span className="flex-shrink-0 w-8 h-8 rounded-full bg-primary/10 text-primary flex items-center justify-center font-display font-bold text-sm ring-4 ring-background">
                                {i + 1}
                              </span>
                              <div className="flex-1 pr-16">
                                <div className="text-xs font-bold uppercase tracking-wider text-muted-foreground mb-1">{activity.type}</div>
                                {isEditing ? (
                                   <div className="tag bg-accent text-accent-foreground mb-2">Editing...</div>
                                ) : (
                                  <div className="font-medium text-lg text-foreground leading-relaxed whitespace-pre-wrap">
                                    {activity.question}
                                  </div>
                                )}
                              </div>
                            </div>

                            {isEditing ? (
                              <div className="mt-4 pt-4 border-t border-border/50 animate-scale-in">
                                <EditActivityPanel
                                  key={activity.id}
                                  activity={activity}
                                  busy={isSaving}
                                  error={editError}
                                  onSubmit={(payload) => handleEditSubmit(activity.id, payload)}
                                  onCancel={cancelEditingActivity}
                                />
                              </div>
                            ) : (
                              <div className="mt-4 pl-12">
                                <ActivityDetailsCard activity={activity} />
                              </div>
                            )}

                            {/* Configuration Grid */}
                            <div className="grid md:grid-cols-2 gap-4 pl-12 pt-4 border-t border-border/50">

                              {/* Topics Config */}
                              <div className="rounded-xl border border-dashed border-border bg-secondary/20 p-4 space-y-3 hover:border-accent/50 transition-colors">
                                <div className="flex items-center justify-between">
                                  <div className="text-xs font-bold uppercase tracking-wider text-muted-foreground flex items-center gap-1">
                                    <Sparkles className="w-3 h-3" /> Topics
