                                {topics.length === 0 ? (
                                  <p className="text-xs text-muted-foreground italic">
                                    No course topics available. Add them in the sidebar.
                                  </p>
                                ) : (
                                  <div className="space-y-3">
                                    <div>
                                      <label className="text-xs font-semibold text-foreground block mb-1.5">
                                        Main Topic
