                                        value={mainTopicId}
                                        onChange={(event) =>
                                          handleActivityMainTopicChange(activity.id, event.target.value)
                                        }
                                        disabled={loadingTopics || isUpdatingTopics}
                                        className={`w-full text-sm rounded-lg border-border bg-background focus:ring-primary focus:border-primary ${
                                          showTopicSaving ? 'disabled:opacity-60' : ''
                                        }`}
                                      >
                                        <option value="">Select a topic…</option>
                                        {topics.map((topic) => (
                                          <option key={topic.id} value={topic.id}>
                                            {topic.name}
                                          </option>
                                        ))}
                                      </select>
                                    </div>
                                    <div>
                                      <span className="text-xs font-semibold text-foreground block mb-2">
                                        Secondary Topics
                                      </span>
                                      <div className="flex flex-wrap gap-2">
                                        {topics
                                          .filter((topic) => topic.id !== mainTopicId)
                                          .map((topic) => {
                                            const checked = secondaryIds.has(topic.id);
                                            return (
                                              <label
                                                key={topic.id}
                                                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full border text-xs cursor-pointer transition-all duration-200 ${
                                                  checked
                                                    ? 'border-accent bg-accent/10 text-accent-foreground font-medium'
                                                    : 'border-border bg-background text-muted-foreground hover:border-primary/50'
                                                } ${
                                                  showTopicSaving && isUpdatingTopics ? 'opacity-60 cursor-wait' : ''
                                                }`}
                                              >
                                                <input
                                                  type="checkbox"
                                                  className="sr-only"
                                                  checked={checked}
                                                  disabled={isUpdatingTopics}
                                                  onChange={(event) =>
                                                    handleActivitySecondaryToggle(
                                                      activity.id,
                                                      topic.id,
                                                      event.target.checked,
                                                    )
                                                  }
                                                />
                                                {topic.name}
                                              </label>
                                            );
                                          })}
                                      </div>
                                    </div>
                                  </div>
                                )}
                              </div>

                              {/* AI Modes Config */}
                              <div className="rounded-xl border border-dashed border-primary/20 bg-primary/5 p-4 space-y-3 hover:border-primary/40 transition-colors">
                                <div className="flex items-center justify-between">
                                  <div className="text-xs font-bold uppercase tracking-wider text-primary flex items-center gap-1">
                                    <Sparkles className="w-3 h-3" /> AI Tutor Modes
                                  </div>
                                  {showModeSaving && isUpdatingModes && (
                                    <span className="text-[0.65rem] text-primary animate-pulse">Saving...</span>
                                  )}
                                </div>

                                <div className="space-y-2">
                                  <label className="flex items-center gap-3 cursor-pointer p-2 rounded-lg hover:bg-primary/5 transition-colors">
                                    <input
                                      type="checkbox"
                                      checked={activity.enableTeachMode}
                                      onChange={(e) => handleActivityModeChange(activity.id, 'teach', e.target.checked)}
                                      disabled={isUpdatingModes}
                                      className="rounded border-primary/50 text-primary focus:ring-primary w-4 h-4"
                                    />
                                    <span className="text-sm font-medium text-foreground">Teach me</span>
                                  </label>
                                  <label className="flex items-center gap-3 cursor-pointer p-2 rounded-lg hover:bg-primary/5 transition-colors">
                                    <input
                                      type="checkbox"
                                      checked={activity.enableGuideMode}
                                      onChange={(e) => handleActivityModeChange(activity.id, 'guide', e.target.checked)}
                                      disabled={isUpdatingModes}
                                      className="rounded border-primary/50 text-primary focus:ring-primary w-4 h-4"
                                    />
                                    <span className="text-sm font-medium text-foreground">Guide me</span>
                                  </label>
                                  <label className="flex items-center gap-3 cursor-pointer p-2 rounded-lg hover:bg-primary/5 transition-colors">
                                    <input
                                      type="checkbox"
                                      checked={activity.enableCustomMode}
                                      onChange={(e) =>
                                        handleActivityModeChange(activity.id, 'custom', e.target.checked)
                                      }
                                      disabled={isUpdatingModes}
                                      className="rounded border-primary/50 text-primary focus:ring-primary w-4 h-4"
                                    />
                                    <span className="text-sm font-medium text-foreground">Custom prompt</span>
                                  </label>
                                </div>

                                {isCustomEnabled && (
                                  <div className="mt-3 space-y-3 pt-3 border-t border-primary/10 animate-fade-in">
                                    <div>
                                      <label className="text-xs font-semibold text-foreground block mb-1">
                                        Button Label (max 20 chars)
                                      </label>
                                      <input
                                        type="text"
                                        value={titleDrafts[activity.id] ?? activity.customPromptTitle ?? ''}
                                        onChange={(event) => {
                                          const value = event.target.value.slice(0, 20);
                                          setTitleDrafts((prev) => ({ ...prev, [activity.id]: value }));
                                          setPromptSaved((saved) => ({ ...saved, [activity.id]: false }));
                                        }}
                                        placeholder="e.g., Explain simply"
                                        maxLength={20}
                                        className="w-full text-sm rounded-lg border-border bg-background focus:ring-primary focus:border-primary"
                                        disabled={isSavingPrompt}
                                      />
                                    </div>
                                    <div>
                                      <label className="text-xs font-semibold text-foreground block mb-1">
                                        System Prompt
                                      </label>
                                      <textarea
                                        value={promptDraft}
                                        onChange={(event) =>
                                          setPromptDrafts((prev) => {
                                            setPromptSaved((saved) => ({ ...saved, [activity.id]: false }));
                                            return {
                                              ...prev,
                                              [activity.id]: event.target.value,
                                            };
                                          })
                                        }
                                        placeholder="Instructions for the AI..."
                                        rows={3}
                                        className="w-full text-sm rounded-lg border-border bg-background focus:ring-primary focus:border-primary resize-none"
                                        disabled={isSavingPrompt}
                                      />
                                      <div className="text-[0.65rem] text-muted-foreground mt-1.5 leading-normal">
                                        Shortcuts: <code className="bg-secondary px-1 rounded text-foreground">[INSERT TOPIC HERE]</code>, <code className="bg-secondary px-1 rounded text-foreground">[ENTER KNOWLEDGE LEVEL]</code>
                                      </div>
                                    </div>
                                    <div className="flex items-center gap-3 pt-1">
                                      <button
                                        type="button"
                                        onClick={() => handleCustomPromptSave(activity)}
                                        disabled={isSavingPrompt}
                                        className="btn-primary text-xs py-1.5 h-8"
                                      >
                                        {isSavingPrompt ? 'Saving…' : isPromptSaved ? 'Saved' : 'Save Config'}
                                      </button>
                                      {promptError && (
                                        <div className="flex items-center gap-1 text-xs text-destructive">
                                          <AlertCircle className="w-3 h-3" />
                                          {promptError}
                                        </div>
                                      )}
                                    </div>
                                  </div>
                                )}
                              </div>
                            </div>
                          </li>
                        );
                      })}
                    </ul>
                  )}
                </div>

                <div className="flex justify-center pt-4">
                  <button
                    type="button"
                    onClick={() => setShowAddPanel((open) => !open)}
                    className="btn-primary shadow-xl shadow-primary/20 scale-105 hover:scale-110"
                  >
                    {showAddPanel ? 'Close Panel' : <><PlusCircle className="w-4 h-4" /> Add New Activity</>}
                  </button>
                </div>

                {showAddPanel && numericLessonId !== null && (
                  <div className="animate-fade-up">
                     <AddActivityPanel
                       lessonId={numericLessonId}
                       onActivityCreated={refreshActivities}
                     />
                  </div>
                )}
              </div>

              {/* Sidebar: Course Topics */}
              <aside className="lg:sticky lg:top-24 space-y-6">
                <div className="card-editorial p-6 space-y-5 shadow-lg shadow-black/5 animate-fade-in delay-150">
                  <div className="flex items-center justify-between border-b border-border pb-4">
                    <div>
                      <h3 className="font-display font-bold text-foreground">Course Topics</h3>
                      {lesson?.courseOfferingId && (
                        <p className="text-xs text-muted-foreground mt-0.5">Course #{lesson.courseOfferingId}</p>
                      )}
                    </div>
                    <div className="h-8 w-8 rounded-full bg-secondary flex items-center justify-center text-muted-foreground">
                       <Sparkles className="w-4 h-4" />
                    </div>
                  </div>

                  {topicsError && (
                    <div className="p-3 rounded-lg bg-destructive/10 text-destructive text-xs border border-destructive/20">
                      {topicsError}
                    </div>
                  )}

                  <div className="space-y-2">
                    {!!course?.externalId || course?.externalSource === 'EDUAI' ? (
                      // EduAI course: Show only sync button
                      lesson?.courseOfferingId && (
                        <SyncTopicsButton
                          courseId={lesson.courseOfferingId}
                          syncing={syncingTopics}
                          onSync={async () => {
                            if (!lesson?.courseOfferingId) return;
                            setSyncingTopics(true);
                            try {
                              const result = await api.syncCourseTopics(lesson.courseOfferingId);
                              // Refresh topics first so the dialog options reflect latest topics
                              await courseTopics.refresh();
                              if (result && Array.isArray(result.missingTopics) && result.missingTopics.length > 0) {
                                setMissingTopics(result.missingTopics.map((t: any) => ({ id: t.id, name: t.name })));
                                setShowMapping(true);
                              }
                            } catch (e) {
                              console.error('Failed to sync topics', e);
                              alert('Failed to sync topics from EduAI. Please try again.');
                            } finally {
                              setSyncingTopics(false);
                            }
                          }}
                        />
                      )
                    ) : (
                      // Regular course: Show add topics button
                      <AddCourseTopicsButton
                        disabled={!lesson?.courseOfferingId}
                      />
                    )}
                  </div>

                  <div className="bg-muted/30 rounded-xl p-3 min-h-[100px] max-h-[300px] overflow-y-auto custom-scrollbar">
                    {topics.length === 0 ? (
                      <div className="text-center py-8 text-muted-foreground text-xs italic">
                        No topics defined yet.
                      </div>
                    ) : (
                      <div className="flex flex-wrap gap-2">
                        {topics.map((topic) => (
                          <div key={topic.id} className="tag bg-background border border-border hover:border-primary/50 transition-colors">
                            {topic.name}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </aside>
            </div>
        </div>
      </div>
      <TopicSyncMappingDialog
        open={showMapping}
        onClose={() => setShowMapping(false)}
        topics={topics}
        missing={missingTopics}
        busy={syncingTopics}
        onApply={async (mappings) => {
          if (!lesson?.courseOfferingId) return;
          await api.remapCourseTopics(lesson.courseOfferingId, mappings);
          await Promise.all([courseTopics.refresh(), refreshActivities()]);
        }}
      />
    </CourseTopicsProvider>
  );
}
