                >
                  Cancel
                </button>
                <button
                  onClick={handleConfirmKnowledge}
                  disabled={!tempKnowledgeLevel}
                  className="btn-primary flex-[2]"
                >
                  Start Learning
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
