        <div className="grid gap-8 lg:grid-cols-[1.5fr_1fr] items-start">

          {/* Left Column: Question & Answer */}
          <div className="space-y-6">

            {/* Question Card */}
            <div className="card-editorial p-6 sm:p-8 animate-fade-up shadow-xl shadow-black/5">
              <div className="flex items-center gap-3 mb-6">
                <span className="px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-bold uppercase tracking-wider">
                  Question {idx + 1}
                </span>
                {activity?.mainTopic && (
                   <span className="px-3 py-1 rounded-full bg-accent/10 text-accent-foreground text-xs font-bold uppercase tracking-wider flex items-center gap-1">
                     <Sparkles className="w-3 h-3" />
                     {activity.mainTopic.name}
                   </span>
                )}
              </div>

              <div className="prose prose-lg dark:prose-invert max-w-none text-foreground font-medium leading-relaxed">
                {questionChunks.map((line, index) => (
                  <p key={index} className="mb-4 last:mb-0">
                    {line}
                  </p>
                ))}
              </div>

              {activity?.secondaryTopics && activity.secondaryTopics.length > 0 && (
                <div className="mt-8 pt-6 border-t border-border/50">
                  <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-3">Related Topics</span>
                  <div className="flex flex-wrap gap-2">
                    {activity.secondaryTopics.map((topic) => (
                      <span key={topic.id} className="tag bg-secondary/50 text-secondary-foreground border border-transparent hover:border-primary/20 transition-colors">
                        {topic.name}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Answer Area */}
            <div className="card-editorial p-6 sm:p-8 animate-fade-up delay-100 shadow-lg shadow-black/5">
              <h2 className="font-display text-xl font-bold text-foreground mb-6 flex items-center gap-2">
                Your Answer
              </h2>

              {activity?.type === 'MCQ' ? (
                Array.isArray(activity?.options?.choices) ? (
                  <div className="space-y-3">
                    {activity.options.choices.map((choice, i) => (
                      <label
                        key={i}
                        className={`group flex items-start gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all duration-200 ${
                          mcq === i
                            ? 'border-primary bg-primary/5 shadow-md shadow-primary/5'
                            : 'border-border hover:border-primary/30 hover:bg-muted/30'
                        }`}
                      >
                        <input
                          type="radio"
                          className="sr-only"
                          name="mcq"
                          checked={mcq === i}
                          onChange={() => setMcq(i)}
                        />
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm font-bold flex-shrink-0 transition-colors ${
                          mcq === i 
                            ? 'bg-primary text-primary-foreground' 
                            : 'bg-muted text-muted-foreground group-hover:bg-muted/80'
                        }`}>
                          {String.fromCharCode(65 + i)}
                        </div>
                        <span className="text-foreground pt-1 text-lg">{choice}</span>
                      </label>
                    ))}
                  </div>
                ) : (
                  <div className="p-4 rounded-xl bg-destructive/10 text-destructive border border-destructive/20 flex items-center gap-2">
                    <XCircle className="w-5 h-5" />
                    This question's options are misconfigured.
                  </div>
                )
              ) : (
                <div className="relative">
                  <textarea
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder="Type your answer here..."
                    rows={4}
                    className="w-full p-4 rounded-xl border-2 border-border bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all text-lg resize-none"
                  />
                  <div className="absolute bottom-3 right-3 text-xs text-muted-foreground">
                    {text.length} chars
                  </div>
                </div>
              )}

              {/* Action Bar */}
              <div className="flex flex-wrap items-center gap-4 pt-6 mt-2">
                <button
                  onClick={submit}
                  disabled={
                    submitting ||
                    (activity?.type === 'MCQ' ? mcq === null : text.trim() === '')
                  }
                  className="btn-primary shadow-xl shadow-primary/20 hover:shadow-primary/30 min-w-[140px]"
                >
                  {submitting ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Checking...
                    </>
                  ) : (
                    <>
                      <CheckCircle2 className="w-4 h-4" />
                      Submit Answer
                    </>
                  )}
                </button>

                <button
                  onClick={handleGuideMe}
                  disabled={wasCorrect || !currentKnowledgeLevel || !isUserReady}
                  className="btn-secondary"
                >
                  <Lightbulb className="w-4 h-4" />
                  Guide Me
                </button>

                <div className="flex-1" />

                <div className="flex items-center gap-2 bg-muted/30 p-1 rounded-lg border border-border">
                  <button
                    disabled={!canPrev}
                    onClick={() => {
                      setIdx((i) => Math.max(0, i - 1));
                      resetForNavigation();
                    }}
                    className="p-2 rounded-md hover:bg-background hover:shadow-sm text-muted-foreground hover:text-foreground disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                    title="Previous Question"
                  >
                    <ChevronLeft className="w-5 h-5" />
                  </button>
                  <div className="w-px h-4 bg-border" />
                  <button
                    disabled={!canNext}
                    onClick={() => {
                      setIdx((i) => Math.min(orderedActivities.length - 1, i + 1));
                      resetForNavigation();
                    }}
                    className="p-2 rounded-md hover:bg-background hover:shadow-sm text-muted-foreground hover:text-foreground disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                    title="Next Question"
                  >
                    <ChevronRight className="w-5 h-5" />
                  </button>
                </div>
              </div>

              {/* Feedback Alert */}
              {result && (
                <div className={`mt-6 p-4 rounded-xl flex items-start gap-3 animate-scale-in border ${
                  wasCorrect 
                    ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-700 dark:text-emerald-400' 
                    : 'bg-amber-500/10 border-amber-500/20 text-amber-700 dark:text-amber-400'
                }`}>
                  <div className={`mt-0.5 p-1 rounded-full ${
                    wasCorrect ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'
                  }`}>
                    {wasCorrect ? <CheckCircle2 className="w-4 h-4" /> : <HelpCircle className="w-4 h-4" />}
                  </div>
                  <div>
                    <p className="font-bold text-lg">{result}</p>
                    {wasCorrect && (
                       <p className="text-sm opacity-90 mt-1">Great job! The AI Tutor has some additional insights for you in the chat.</p>
                    )}
                  </div>
                </div>
              )}

              {activity &&
                currentFeedback.promptShown &&
                !currentFeedback.dismissed &&
                (currentFeedback.promptVisible || currentFeedback.submitted) && (
                <div className="mt-6 animate-fade-in border-t border-border/50 pt-6">
                  <StudentActivityFeedbackCard
                    rating={currentFeedback.rating}
                    note={currentFeedback.note}
                    saving={currentFeedback.saving}
                    submitted={currentFeedback.submitted}
                    error={currentFeedback.error}
                    onSelectRating={handleFeedbackRating}
                    onNoteChange={handleFeedbackNote}
                    onSubmit={handleSubmitFeedback}
                    onDismiss={handleDismissFeedback}
                  />
                </div>
              )}
            </div>
          </div>

          {/* Right Column: AI Chat */}
          <div className="lg:sticky lg:top-24 h-[calc(100vh-8rem)] min-h-[600px] flex flex-col">
            <div className="flex-1 bg-card border border-border rounded-2xl shadow-xl shadow-black/5 overflow-hidden flex flex-col animate-slide-in-right">
              <div className="bg-muted/30 border-b border-border p-4 flex items-center gap-2">
                 <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                    <MessageCircle className="w-4 h-4" />
                 </div>
                 <h3 className="font-display font-bold text-foreground">AI Tutor</h3>
              </div>

              <div className="flex-1 overflow-hidden relative">
                <StudentAiChat
                  key={activity?.id ?? 'none'}
                  ref={chatRef}
                  activity={activity}
                  isUserReady={isUserReady}
                  knowledgeLevel={currentKnowledgeLevel}
                  onRequestKnowledgeLevel={handleRequestKnowledgeLevel}
                  onAdjustKnowledgeLevel={handleAdjustKnowledgeLevel}
                  topicOptions={topicOptions}
                  currentTopicId={currentTopicId}
                  onSelectTopic={handleTopicSelect}
                  studentAnswer={studentAnswer}
                />
              </div>
            </div>
          </div>

        </div>

        {/* Pre-Chat Modal */}
        {showKnowledgeModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
            <div className="max-w-lg w-full card-editorial p-8 space-y-6 animate-in zoom-in-95 duration-200 shadow-2xl">
              <div className="text-center">
                <div className="w-16 h-16 mx-auto rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-6 shadow-lg shadow-primary/10 ring-4 ring-background">
                  <Sparkles className="w-8 h-8" />
                </div>
                <h2 className="font-display text-2xl font-bold text-foreground">
                  Personalize Your Learning
                </h2>
                <p className="text-muted-foreground mt-2 max-w-xs mx-auto">
                  To give you the best guidance, the AI needs to know your familiarity with this topic.
                </p>
              </div>

              <div className="space-y-4">
                <label className="block text-sm font-semibold text-foreground text-center uppercase tracking-wide opacity-70">
                  Select Knowledge Level
                </label>
                <div className="grid grid-cols-1 gap-3">
                  {[
                    { value: 'beginner', label: 'Beginner', desc: "I'm new to this concept" },
                    { value: 'intermediate', label: 'Intermediate', desc: 'I have some experience' },
                    { value: 'advanced', label: 'Advanced', desc: 'I feel confident about this' },
                  ].map((level) => (
                    <button
                      key={level.value}
                      type="button"
                      onClick={() => setTempKnowledgeLevel(level.value)}
                      className={`group relative p-4 rounded-xl border-2 text-left transition-all duration-200 ${
                        tempKnowledgeLevel === level.value
                          ? 'border-primary bg-primary/5 shadow-md shadow-primary/5 z-10'
                          : 'border-border hover:border-primary/30 hover:bg-muted/50'
                      }`}
                    >
                      <div className="flex items-center justify-between">
                         <div className="font-bold text-foreground">{level.label}</div>
                         {tempKnowledgeLevel === level.value && <CheckCircle2 className="w-5 h-5 text-primary" />}
                      </div>
                      <div className="text-sm text-muted-foreground mt-0.5 group-hover:text-foreground/80 transition-colors">{level.desc}</div>
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex gap-3 pt-4 border-t border-border/50">
                <button
                  onClick={handleCancelKnowledge}
                  className="btn-ghost flex-1"
                >
                  Cancel
                </button>
                <button
                  onClick={handleConfirmKnowledge}
                  disabled={!tempKnowledgeLevel}
                  className="btn-primary flex-[2]"
                >
                  Start Learning
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
