cat <<'EOF' > app/routes/student.list.tsx
import { useCallback, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router';
import Nav from '../components/Nav';
import { ProgressBar } from '../components/ProgressBar';
import StudentActivityFeedbackCard from '../components/StudentActivityFeedbackCard';
import StudentAiChat, { type StudentAiChatHandle } from '../components/StudentAiChat';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import api from '../lib/api';
import type { Activity, Course, Lesson, ModuleDetail } from '../lib/types';
import type { Route } from './+types/student.list';
import { requireClientUser } from '~/lib/client-auth';
import { useLocalUser } from '~/hooks/useLocalUser';
import { 
  BookOpen, 
  CheckCircle2, 
  ChevronLeft, 
  ChevronRight, 
  HelpCircle, 
  Lightbulb, 
  MessageCircle, 
  Send,
  XCircle,
  Sparkles
} from 'lucide-react';

type StudentFeedbackState = {
  rating: number | null;
  note: string;
  promptShown: boolean;
  promptVisible: boolean;
  submitted: boolean;
  dismissed: boolean;
  saving: boolean;
  error: string | null;
};

type FeedbackApi = typeof api & {
  submitActivityFeedback?: (
    activityId: number,
    payload: { rating: number; note?: string },
  ) => Promise<{ ok?: boolean }>;
};

function createFeedbackState(): StudentFeedbackState {
  return {
    rating: null,
    note: '',
    promptShown: false,
    promptVisible: false,
    submitted: false,
    dismissed: false,
    saving: false,
    error: null,
  };
}

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('STUDENT');
  const lessonId = Number(params.lessonId);
  if (!Number.isFinite(lessonId)) {
    throw new Response('Invalid lesson id', { status: 400 });
  }

  const [lesson, activities] = await Promise.all([
    api.lessonById(lessonId) as Promise<Lesson>,
    api.activitiesForLesson(lessonId) as Promise<Activity[]>,
  ]);

  let module: ModuleDetail | null = null;
  let course: Course | null = null;
  if (lesson.moduleId) {
    module = (await api.moduleById(lesson.moduleId)) as ModuleDetail;
    if (module?.courseOfferingId) {
      course = (await api.courseById(module.courseOfferingId)) as Course;
    }
  }

  return { course, module, lesson, activities };
}

export default function StudentLessonPlayer({ loaderData }: Route.ComponentProps) {
  const { user } = useLocalUser();
  const { course, module, lesson, activities } = loaderData;
  const [orderedActivities, setOrderedActivities] = useState<Activity[]>(activities ?? []);
  const [idx, setIdx] = useState(0);
  const [mcq, setMcq] = useState<number | null>(null);
  const [text, setText] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [wasCorrect, setWasCorrect] = useState(false);
  const [prevActivityId, setPrevActivityId] = useState<number | null>(null);

  // Pre-chat context for AI guidance
  const [showKnowledgeModal, setShowKnowledgeModal] = useState(false);
  const [tempKnowledgeLevel, setTempKnowledgeLevel] = useState('');
  const [knowledgeLevels, setKnowledgeLevels] = useState<Record<number, string>>({});
  const [topicSelection, setTopicSelection] = useState<Record<number, number>>({});
  const [feedbackByActivity, setFeedbackByActivity] = useState<Record<number, StudentFeedbackState>>({});
  const chatRef = useRef<StudentAiChatHandle>(null);

  // Adjust state during render when loader data changes
  const [prevActivities, setPrevActivities] = useState(activities);
  if (activities !== prevActivities) {
    setPrevActivities(activities);
    setOrderedActivities(activities ?? []);
  }

  const activity = orderedActivities[idx];
  const canNext = idx < orderedActivities.length - 1;
  const canPrev = idx > 0;

  const questionChunks = useMemo(
    () => (activity?.question || '').split(/\n/),
    [activity?.question],
  );

  const currentKnowledgeLevel = activity ? knowledgeLevels[activity.id] ?? null : null;
  const currentTopicId = activity
    ? topicSelection[activity.id] ?? activity.mainTopic?.id ?? null
    : null;
  const currentFeedback = activity ? feedbackByActivity[activity.id] ?? createFeedbackState() : createFeedbackState();
  const studentAnswer = activity
    ? activity.type === 'MCQ'
      ? mcq
      : text
    : null;
  const isUserReady = Boolean(user);

  const currentActivityId = activity?.id ?? null;
  if (currentActivityId !== prevActivityId) {
    setPrevActivityId(currentActivityId);
    setWasCorrect(false);
    setResult(null);
    setTempKnowledgeLevel('');
    setShowKnowledgeModal(false);
    setMcq(null);
    setText('');
  }

  const submit = async () => {
    if (!activity || !user) return;
    setSubmitting(true);
    try {
      const payload: any = { userId: user.id };
      if (activity.type === 'MCQ') payload.answerOption = mcq;
      else payload.answerText = text;
      const res = await api.submitAnswer(activity.id, payload);
      setResult(res.isCorrect ? 'Correct!' : 'Not quite. Keep going!');

      setOrderedActivities((prev) =>
        prev.map((a, i) =>
          i === idx ? { ...a, completionStatus: res.isCorrect ? ('correct' as const) : undefined } : a
        )
      );

      if (res.isCorrect) {
        setWasCorrect(true);
        chatRef.current?.pushGuideMessage(
          res.message || 'Great job! Proceed when you are ready for the next question.',
        );
      } else {
        setWasCorrect(false);
      }

      setFeedbackByActivity((prev) => {
        const current = prev[activity.id] ?? createFeedbackState();
        if (
          current.promptShown ||
          current.submitted ||
          current.dismissed ||
          res.feedbackRequired === false ||
          res.feedbackAlreadySubmitted
        ) {
          return prev;
        }
        return {
          ...prev,
          [activity.id]: {
            ...current,
            promptShown: true,
            promptVisible: true,
            error: null,
          },
        };
      });
    } catch (e) {
      setResult('There was a problem submitting.');
      setWasCorrect(false);
    } finally {
      setSubmitting(false);
    }
  };

  const resetForNavigation = useCallback(() => {
    setMcq(null);
    setText('');
    setResult(null);
    setWasCorrect(false);
    setTempKnowledgeLevel('');
  }, []);

  const handleRequestKnowledgeLevel = useCallback(() => {
    setTempKnowledgeLevel('');
    setShowKnowledgeModal(true);
  }, []);

  const handleAdjustKnowledgeLevel = useCallback(() => {
    setTempKnowledgeLevel(currentKnowledgeLevel ?? '');
    setShowKnowledgeModal(true);
  }, [currentKnowledgeLevel]);

  const handleTopicSelect = useCallback(
    (topicId: number) => {
      if (!activity) return;
      setTopicSelection((prev) => ({ ...prev, [activity.id]: topicId }));
    },
    [activity],
  );

  const handleGuideMe = useCallback(() => {
    if (!activity || wasCorrect) return;
    chatRef.current?.sendGuidePrompt();
  }, [activity, wasCorrect]);

  const updateFeedbackState = useCallback(
    (updater: (current: StudentFeedbackState) => StudentFeedbackState) => {
      if (!activity) return;
      setFeedbackByActivity((prev) => ({
        ...prev,
        [activity.id]: updater(prev[activity.id] ?? createFeedbackState()),
      }));
    },
    [activity],
  );

  const handleFeedbackRating = useCallback(
    (rating: number) => {
      updateFeedbackState((current) => ({
        ...current,
        rating,
        error: null,
      }));
    },
    [updateFeedbackState],
  );

  const handleFeedbackNote = useCallback(
    (note: string) => {
      updateFeedbackState((current) => ({
        ...current,
        note,
      }));
    },
    [updateFeedbackState],
  );

  const handleDismissFeedback = useCallback(() => {
    updateFeedbackState((current) => ({
      ...current,
      promptVisible: false,
      dismissed: true,
      error: null,
    }));
  }, [updateFeedbackState]);

  const handleSubmitFeedback = useCallback(async () => {
    if (!activity || !currentFeedback.rating) return;

    updateFeedbackState((current) => ({
      ...current,
      saving: true,
      error: null,
    }));

    try {
      const feedbackApi = api as FeedbackApi;
      if (typeof feedbackApi.submitActivityFeedback !== 'function') {
        throw new Error('Feedback service not available');
      }

      await feedbackApi.submitActivityFeedback(activity.id, {
        rating: currentFeedback.rating,
        note: currentFeedback.note.trim() || undefined,
      });

      updateFeedbackState((current) => ({
        ...current,
        saving: false,
        submitted: true,
        promptVisible: false,
        dismissed: false,
        error: null,
      }));
    } catch (error) {
      updateFeedbackState((current) => ({
        ...current,
        saving: false,
        error: 'Could not save feedback right now. Please try again.',
      }));
    }
  }, [activity, currentFeedback.note, currentFeedback.rating, updateFeedbackState]);

  const handleConfirmKnowledge = () => {
    if (!activity || !tempKnowledgeLevel) {
      return;
    }
    setKnowledgeLevels((prev) => ({ ...prev, [activity.id]: tempKnowledgeLevel }));
    setShowKnowledgeModal(false);
  };

  const handleCancelKnowledge = () => {
    setShowKnowledgeModal(false);
  };

  const topicOptions = activity
    ? [
        ...(activity.mainTopic ? [{ label: activity.mainTopic.name, value: activity.mainTopic.id }] : []),
        ...activity.secondaryTopics.map((topic) => ({ label: topic.name, value: topic.id })),
      ]
    : [];

  return (
    <div className="min-h-dvh bg-background selection:bg-primary/10">
      <Nav />

      {/* Immersive Header */}
      <div className="relative border-b border-border/40 bg-muted/20 pb-12 pt-8 overflow-hidden">
        <div className="absolute inset-0 dots-pattern opacity-30" />
        <div className="absolute top-1/2 right-1/4 h-64 w-64 rounded-full bg-primary/5 blur-3xl" />

        <div className="container relative mx-auto px-6 z-10">
          <Breadcrumb className="mb-6">
            <BreadcrumbList>
              <BreadcrumbItem>
                <BreadcrumbLink asChild>
                  <Link to="/student" className="hover:text-primary transition-colors">My Courses</Link>
                </BreadcrumbLink>
              </BreadcrumbItem>
              <BreadcrumbSeparator />
              <BreadcrumbItem>
                {course && module ? (
                  <BreadcrumbLink asChild>
                    <Link to={`/student/courses/${module.courseOfferingId}`} className="hover:text-primary transition-colors">{course.title}</Link>
                  </BreadcrumbLink>
                ) : (
                  <BreadcrumbPage>Course</BreadcrumbPage>
                )}
              </BreadcrumbItem>
              <BreadcrumbSeparator />
              <BreadcrumbItem>
                {module && lesson ? (
                  <BreadcrumbLink asChild>
                    <Link to={`/student/module/${lesson.moduleId}`} className="hover:text-primary transition-colors">{module.title}</Link>
                  </BreadcrumbLink>
                ) : (
                  <BreadcrumbPage>Module</BreadcrumbPage>
                )}
              </BreadcrumbItem>
              <BreadcrumbSeparator />
              <BreadcrumbItem>
                <BreadcrumbPage>{lesson?.title || 'Lesson'}</BreadcrumbPage>
              </BreadcrumbItem>
            </BreadcrumbList>
          </Breadcrumb>

          <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-8">
            <div className="max-w-3xl">
              <div className="flex items-center gap-3 mb-3">
                 <div className="h-12 w-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary shadow-sm shadow-primary/5">
                    <BookOpen className="h-6 w-6" />
                 </div>
                 <h1 className="font-display text-3xl sm:text-4xl font-bold tracking-tight text-foreground">
                   {lesson?.title || 'Lesson Player'}
                 </h1>
              </div>
              <div className="flex items-center gap-2 text-muted-foreground text-lg">
                <span>Question {idx + 1}</span>
                <span className="text-border">/</span>
                <span>{orderedActivities.length}</span>
              </div>
            </div>

            {/* Progress Bar in Header */}
            <div className="w-full lg:w-1/3 bg-background/50 backdrop-blur-sm rounded-2xl p-4 border border-border/50 shadow-sm">
               <div className="flex items-center justify-between text-xs font-medium text-muted-foreground mb-2">
                 <span>Your Progress</span>
                 <span>{Math.round((orderedActivities.filter(a => a.completionStatus === 'correct').length / orderedActivities.length) * 100)}%</span>
               </div>
               <ProgressBar
                completed={orderedActivities.filter((a) => a.completionStatus === 'correct').length}
                total={orderedActivities.length}
                size="sm"
                showLabel={false}
              />
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-6 -mt-8 relative z-10 pb-20">
        <div className="grid gap-8 lg:grid-cols-[1.5fr_1fr] items-start">

          {/* Left Column: Question & Answer */}
          <div className="space-y-6">

            {/* Question Card */}
            <div className="card-editorial p-6 sm:p-8 animate-fade-up shadow-xl shadow-black/5">
              <div className="flex items-center gap-3 mb-6">
                <span className="px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-bold uppercase tracking-wider">
                  Question {idx + 1}
                </span>
                {activity?.mainTopic && (
                   <span className="px-3 py-1 rounded-full bg-accent/10 text-accent-foreground text-xs font-bold uppercase tracking-wider flex items-center gap-1">
                     <Sparkles className="w-3 h-3" />
                     {activity.mainTopic.name}
                   </span>
                )}
              </div>

              <div className="prose prose-lg dark:prose-invert max-w-none text-foreground font-medium leading-relaxed">
                {questionChunks.map((line, index) => (
                  <p key={index} className="mb-4 last:mb-0">
                    {line}
                  </p>
                ))}
              </div>

              {activity?.secondaryTopics && activity.secondaryTopics.length > 0 && (
                <div className="mt-8 pt-6 border-t border-border/50">
                  <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider block mb-3">Related Topics</span>
                  <div className="flex flex-wrap gap-2">
                    {activity.secondaryTopics.map((topic) => (
                      <span key={topic.id} className="tag bg-secondary/50 text-secondary-foreground border border-transparent hover:border-primary/20 transition-colors">
                        {topic.name}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Answer Area */}
            <div className="card-editorial p-6 sm:p-8 animate-fade-up delay-100 shadow-lg shadow-black/5">
              <h2 className="font-display text-xl font-bold text-foreground mb-6 flex items-center gap-2">
                Your Answer
              </h2>

              {activity?.type === 'MCQ' ? (
                Array.isArray(activity?.options?.choices) ? (
                  <div className="space-y-3">
                    {activity.options.choices.map((choice, i) => (
                      <label
                        key={i}
                        className={`group flex items-start gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all duration-200 ${
                          mcq === i
                            ? 'border-primary bg-primary/5 shadow-md shadow-primary/5'
                            : 'border-border hover:border-primary/30 hover:bg-muted/30'
                        }`}
                      >
                        <input
                          type="radio"
                          className="sr-only"
                          name="mcq"
                          checked={mcq === i}
                          onChange={() => setMcq(i)}
                        />
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm font-bold flex-shrink-0 transition-colors ${
                          mcq === i 
                            ? 'bg-primary text-primary-foreground' 
                            : 'bg-muted text-muted-foreground group-hover:bg-muted/80'
                        }`}>
                          {String.fromCharCode(65 + i)}
                        </div>
                        <span className="text-foreground pt-1 text-lg">{choice}</span>
                      </label>
                    ))}
                  </div>
                ) : (
                  <div className="p-4 rounded-xl bg-destructive/10 text-destructive border border-destructive/20 flex items-center gap-2">
                    <XCircle className="w-5 h-5" />
                    This question's options are misconfigured.
                  </div>
                )
              ) : (
                <div className="relative">
                  <textarea
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder="Type your answer here..."
                    rows={4}
                    className="w-full p-4 rounded-xl border-2 border-border bg-background focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all text-lg resize-none"
                  />
                  <div className="absolute bottom-3 right-3 text-xs text-muted-foreground">
                    {text.length} chars
                  </div>
                </div>
              )}

              {/* Action Bar */}
              <div className="flex flex-wrap items-center gap-4 pt-6 mt-2">
                <button
                  onClick={submit}
                  disabled={
                    submitting ||
                    (activity?.type === 'MCQ' ? mcq === null : text.trim() === '')
                  }
                  className="btn-primary shadow-xl shadow-primary/20 hover:shadow-primary/30 min-w-[140px]"
                >
                  {submitting ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Checking...
                    </>
                  ) : (
                    <>
                      <CheckCircle2 className="w-4 h-4" />
                      Submit Answer
                    </>
                  )}
                </button>

                <button
                  onClick={handleGuideMe}
                  disabled={wasCorrect || !currentKnowledgeLevel || !isUserReady}
                  className="btn-secondary"
                >
                  <Lightbulb className="w-4 h-4" />
                  Guide Me
                </button>

                <div className="flex-1" />

                <div className="flex items-center gap-2 bg-muted/30 p-1 rounded-lg border border-border">
                  <button
                    disabled={!canPrev}
                    onClick={() => {
                      setIdx((i) => Math.max(0, i - 1));
                      resetForNavigation();
                    }}
                    className="p-2 rounded-md hover:bg-background hover:shadow-sm text-muted-foreground hover:text-foreground disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                    title="Previous Question"
                  >
                    <ChevronLeft className="w-5 h-5" />
                  </button>
                  <div className="w-px h-4 bg-border" />
                  <button
                    disabled={!canNext}
                    onClick={() => {
                      setIdx((i) => Math.min(orderedActivities.length - 1, i + 1));
                      resetForNavigation();
                    }}
                    className="p-2 rounded-md hover:bg-background hover:shadow-sm text-muted-foreground hover:text-foreground disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                    title="Next Question"
                  >
                    <ChevronRight className="w-5 h-5" />
                  </button>
                </div>
              </div>

              {/* Feedback Alert */}
              {result && (
                <div className={`mt-6 p-4 rounded-xl flex items-start gap-3 animate-scale-in border ${
                  wasCorrect 
                    ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-700 dark:text-emerald-400' 
                    : 'bg-amber-500/10 border-amber-500/20 text-amber-700 dark:text-amber-400'
                }`}>
                  <div className={`mt-0.5 p-1 rounded-full ${
                    wasCorrect ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'
                  }`}>
                    {wasCorrect ? <CheckCircle2 className="w-4 h-4" /> : <HelpCircle className="w-4 h-4" />}
                  </div>
                  <div>
                    <p className="font-bold text-lg">{result}</p>
                    {wasCorrect && (
                       <p className="text-sm opacity-90 mt-1">Great job! The AI Tutor has some additional insights for you in the chat.</p>
                    )}
                  </div>
                </div>
              )}

              {activity &&
                currentFeedback.promptShown &&
                !currentFeedback.dismissed &&
                (currentFeedback.promptVisible || currentFeedback.submitted) && (
                <div className="mt-6 animate-fade-in border-t border-border/50 pt-6">
                  <StudentActivityFeedbackCard
                    rating={currentFeedback.rating}
                    note={currentFeedback.note}
                    saving={currentFeedback.saving}
                    submitted={currentFeedback.submitted}
                    error={currentFeedback.error}
                    onSelectRating={handleFeedbackRating}
                    onNoteChange={handleFeedbackNote}
                    onSubmit={handleSubmitFeedback}
                    onDismiss={handleDismissFeedback}
                  />
                </div>
              )}
            </div>
          </div>

          {/* Right Column: AI Chat */}
          <div className="lg:sticky lg:top-24 h-[calc(100vh-8rem)] min-h-[600px] flex flex-col">
            <div className="flex-1 bg-card border border-border rounded-2xl shadow-xl shadow-black/5 overflow-hidden flex flex-col animate-slide-in-right">
              <div className="bg-muted/30 border-b border-border p-4 flex items-center gap-2">
                 <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center text-primary">
                    <MessageCircle className="w-4 h-4" />
                 </div>
                 <h3 className="font-display font-bold text-foreground">AI Tutor</h3>
              </div>

              <div className="flex-1 overflow-hidden relative">
                <StudentAiChat
                  key={activity?.id ?? 'none'}
                  ref={chatRef}
                  activity={activity}
                  isUserReady={isUserReady}
                  knowledgeLevel={currentKnowledgeLevel}
                  onRequestKnowledgeLevel={handleRequestKnowledgeLevel}
                  onAdjustKnowledgeLevel={handleAdjustKnowledgeLevel}
                  topicOptions={topicOptions}
                  currentTopicId={currentTopicId}
                  onSelectTopic={handleTopicSelect}
                  studentAnswer={studentAnswer}
                />
              </div>
            </div>
          </div>

        </div>

        {/* Pre-Chat Modal */}
        {showKnowledgeModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-md p-4 animate-in fade-in duration-200">
            <div className="max-w-lg w-full card-editorial p-8 space-y-6 animate-in zoom-in-95 duration-200 shadow-2xl">
              <div className="text-center">
                <div className="w-16 h-16 mx-auto rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-6 shadow-lg shadow-primary/10 ring-4 ring-background">
                  <Sparkles className="w-8 h-8" />
                </div>
                <h2 className="font-display text-2xl font-bold text-foreground">
                  Personalize Your Learning
                </h2>
                <p className="text-muted-foreground mt-2 max-w-xs mx-auto">
                  To give you the best guidance, the AI needs to know your familiarity with this topic.
                </p>
              </div>

              <div className="space-y-4">
                <label className="block text-sm font-semibold text-foreground text-center uppercase tracking-wide opacity-70">
                  Select Knowledge Level
                </label>
                <div className="grid grid-cols-1 gap-3">
                  {[
                    { value: 'beginner', label: 'Beginner', desc: "I'm new to this concept" },
                    { value: 'intermediate', label: 'Intermediate', desc: 'I have some experience' },
                    { value: 'advanced', label: 'Advanced', desc: 'I feel confident about this' },
                  ].map((level) => (
                    <button
                      key={level.value}
                      type="button"
                      onClick={() => setTempKnowledgeLevel(level.value)}
                      className={`group relative p-4 rounded-xl border-2 text-left transition-all duration-200 ${
                        tempKnowledgeLevel === level.value
                          ? 'border-primary bg-primary/5 shadow-md shadow-primary/5 z-10'
                          : 'border-border hover:border-primary/30 hover:bg-muted/50'
                      }`}
                    >
                      <div className="flex items-center justify-between">
                         <div className="font-bold text-foreground">{level.label}</div>
                         {tempKnowledgeLevel === level.value && <CheckCircle2 className="w-5 h-5 text-primary" />}
                      </div>
                      <div className="text-sm text-muted-foreground mt-0.5 group-hover:text-foreground/80 transition-colors">{level.desc}</div>
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex gap-3 pt-4 border-t border-border/50">
                <button
                  onClick={handleCancelKnowledge}
                  className="btn-ghost flex-1"
                >
                  Cancel
                </button>
                <button
                  onClick={handleConfirmKnowledge}
                  disabled={!tempKnowledgeLevel}
                  className="btn-primary flex-[2]"
                >
                  Start Learning
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
