1. import type { Route } from './+types/home';
2. import { useEffect, useState, cloneElement, type ReactElement, type ReactNode } from 'react';
3. import { useNavigate } from 'react-router';
4. import { useLocalUser } from '../hooks/useLocalUser';
5. import { signInWithEduAi } from '../lib/auth-client';
6. import type { Role } from '../lib/types';
7. import { 
8.   BookOpen, 
9.   BrainCircuit, 
10.   GraduationCap, 
11.   LayoutDashboard, 
12.   Library, 
13.   LineChart, 
14.   Sparkles, 
15.   Zap 
16. } from 'lucide-react';
17. 
18. export function meta({}: Route.MetaArgs) {
19.   return [
20.     { title: 'AI Tutor - Welcome' },
21.     { name: 'description', content: 'Sign in to AI Tutor with your EduAI account' },
22.   ];
23. }
24. 
25. function routeForRole(role: Role) {
26.   if (role === 'STUDENT') return '/student';
27.   if (role === 'PROFESSOR') return '/instructor';
28.   if (role === 'TA') return '/unsupported-role';
29.   return '/admin';
30. }
31. 
32. function extractErrorMessage(error: unknown) {
33.   if (!(error instanceof Error)) {
34.     return 'Could not start EduAI sign-in';
35.   }
36. 
37.   try {
38.     const parsed = JSON.parse(error.message);
39.     if (typeof parsed?.message === 'string' && parsed.message.trim()) {
40.       return parsed.message;
41.     }
42.     if (typeof parsed?.error === 'string' && parsed.error.trim()) {
43.       return parsed.error;
44.     }
45.   } catch {
46.     // Fall back to the raw message when the backend returns plain text.
47.   }
48. 
49.   return error.message || 'Could not start EduAI sign-in';
50. }
51. 
52. export default function Home() {
53.   const navigate = useNavigate();
54.   const { user, isInitializing } = useLocalUser();
55.   const [loading, setLoading] = useState(false);
56.   const [error, setError] = useState('');
57. 
58.   useEffect(() => {
59.     if (!user) return;
60.     navigate(routeForRole(user.role), { replace: true });
61.   }, [navigate, user]);
62. 
63.   useEffect(() => {
64.     if (typeof window === 'undefined') return;
65.     const params = new URLSearchParams(window.location.search);
66.     if (params.get('authError') === 'eduai_sign_in_failed') {
67.       setError('EduAI sign-in did not complete. Please try again.');
68.     }
69.   }, []);
70. 
71.   const onSignIn = async () => {
72.     setLoading(true);
73.     setError('');
74. 
75.     try {
76.       await signInWithEduAi();
77.     } catch (err) {
78.       setError(extractErrorMessage(err));
79.       setLoading(false);
80.       return;
81.     } finally {
82.       // Full-page redirect keeps this from usually running, but it protects the button on failure.
83.       setLoading(false);
84.     }
85.   };
86. 
87.   // Loading State
88.   if (isInitializing || user) {
89.     return (
90.       <main className="relative min-h-dvh overflow-hidden bg-background flex items-center justify-center">
